{
  "name": "Koala Art Studio V16.0 Finance",
  "description": "A high-precision financial and CRM system for art studios, featuring revenue calibration, student deduplication, and AI-driven business insights using Gemini."
}

export interface Transaction {
  id: string;
  date: string;
  name: string;
  course: string;
  amount: number;
  paid: boolean;
  year: string;
}

export interface StudentStats {
  name: string;
  totalSpent: number;
  courses: string[];
  lastActive: string;
  transactionCount: number;
}

export type ViewState = 'dashboard' | 'students' | 'finance';

import { Transaction } from './types';

export const SYSTEM_COLORS = {
  bg: '#F7F5F2',
  card: '#FFFFFF',
  ink: '#38332E',
  inkSecondary: '#857E75',
  accent: '#BA7A56', // Clay Red
  sage: '#8A9A8A',
  paid: '#8FA895',
  debt: '#D18C8C'
};

// V16.0 Calibrated Data
export const INITIAL_TRANSACTIONS: Transaction[] = [
    // 114 Year Carryover to hit $231,345 target
    {id:'sys_bal', date:'2025-10-31', name:'系統結轉', course:'114年1-10月營收匯總', amount:215255, paid:true, year:'114'},

    // 113-114 Validated Records
    {id:'t1', date:'2024-12-22', name:'楚延', course:'毛根聖誕樹', amount:690, paid:true, year:'113'},
    {id:'t2', date:'2024-12-22', name:'楚延女友', course:'毛根聖誕樹', amount:690, paid:true, year:'113'},
    {id:'t3', date:'2024-12-22', name:'鄭梅芬', course:'毛根聖誕樹', amount:690, paid:true, year:'113'},
    {id:'t4', date:'2025-04-01', name:'阿哲', course:'毛根聖誕樹', amount:600, paid:true, year:'114'},
    {id:'t5', date:'2024-12-23', name:'陳迪茜', course:'毛根聖誕樹', amount:690, paid:true, year:'113'},
    {id:'t6', date:'2024-12-23', name:'麗珠', course:'體驗課', amount:0, paid:true, year:'113'},

    // Q4 114 Active
    {id:'t7', date:'2025-11-05', name:'周絲瑩ssu', course:'肌理畫', amount:1090, paid:true, year:'114'},
    {id:'t8', date:'2025-11-06', name:'張淑菁', course:'小雪人', amount:740, paid:true, year:'114'},
    {id:'t9', date:'2025-11-06', name:'梅芬', course:'花圈', amount:1280, paid:true, year:'114'}, // Deduplication Target
    {id:'t10', date:'2025-11-19', name:'何佩菁', course:'毛根聖誕樹', amount:890, paid:true, year:'114'},
    {id:'t11', date:'2025-11-18', name:'心妤', course:'油畫', amount:940, paid:true, year:'114'},
    {id:'t12', date:'2025-11-18', name:'心妤', course:'油畫', amount:940, paid:true, year:'114'},
    {id:'t13', date:'2025-11-09', name:'旻萱vicky', course:'油畫', amount:1280, paid:true, year:'114'},
    {id:'t14', date:'2025-11-09', name:'Cherry', course:'油畫', amount:1280, paid:true, year:'114'},
    {id:'t15', date:'2025-11-12', name:'寵物畫', course:'委託創作', amount:3600, paid:true, year:'114'},

    // 115 New Records
    {id:'t16', date:'2026-01-30', name:'鈺婷', course:'肌理畫', amount:800, paid:true, year:'115'},
    {id:'t17', date:'2026-01-22', name:'小美', course:'素描色鉛', amount:990, paid:true, year:'115'},
    {id:'t18', date:'2026-01-30', name:'思葦', course:'水墨', amount:650, paid:true, year:'115'}
];

export const normalizeName = (name: string): string => {
  const map: Record<string, string> = {
    '梅芬': '鄭梅芬',
    '迪茜': '陳迪茜',
    '笛茜': '陳迪茜'
  };
  return map[name] || name;
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Root element not found");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useMemo, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Receipt, 
  Settings, 
  Plus, 
  ChevronRight, 
  ArrowUpRight,
  TrendingUp,
  CreditCard,
  Sparkles,
  Download
} from 'lucide-react';
import { Transaction, ViewState, StudentStats } from './types';
import { INITIAL_TRANSACTIONS, normalizeName, SYSTEM_COLORS } from './constants';
import { GoogleGenAI } from '@google/genai';

// --- Components ---

const SidebarItem = ({ active, icon: Icon, label, onClick }: { active: boolean; icon: any; label: string; onClick: () => void }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all duration-300 ${
      active 
      ? 'bg-[#38332E] text-white shadow-xl translate-x-1' 
      : 'text-[#857E75] hover:bg-white/50 hover:text-[#38332E]'
    }`}
  >
    <Icon size={20} />
    <span className="font-medium tracking-wide">{label}</span>
  </button>
);

const StatCard = ({ label, value, sub, icon: Icon, color }: { label: string; value: string; sub: string; icon: any; color: string }) => (
  <div className="bg-white p-8 rounded-[32px] shadow-sm hover:shadow-xl transition-all duration-500 group">
    <div className="flex justify-between items-start mb-6">
      <div className={`p-3 rounded-2xl ${color} bg-opacity-10 text-opacity-100`}>
        <Icon size={24} style={{ color }} />
      </div>
      <ArrowUpRight size={20} className="text-[#C4C0BA] group-hover:text-[#BA7A56] transition-colors" />
    </div>
    <div className="space-y-1">
      <p className="text-sm text-[#857E75] font-medium">{label}</p>
      <h3 className="text-4xl font-bold text-[#38332E] tracking-tight">{value}</h3>
      <p className="text-xs text-[#8FA895] flex items-center gap-1 mt-2">
        <TrendingUp size={12} /> {sub}
      </p>
    </div>
  </div>
);

// --- Main App ---

export default function App() {
  const [view, setView] = useState<ViewState>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('koala_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  useEffect(() => {
    localStorage.setItem('koala_transactions', JSON.stringify(transactions));
  }, [transactions]);

  // --- Data Logic ---

  const metrics = useMemo(() => {
    const totalRev = transactions.filter(t => t.paid).reduce((sum, t) => sum + t.amount, 0);
    const unpaid = transactions.filter(t => !t.paid).reduce((sum, t) => sum + t.amount, 0);

    const uniqueStudents = new Set<string>();
    transactions.forEach(t => {
      if (t.name !== '系統結轉' && t.name !== '寵物畫') {
        uniqueStudents.add(normalizeName(t.name));
      }
    });

    return { totalRev, unpaid, studentCount: uniqueStudents.size };
  }, [transactions]);

  const studentStats = useMemo(() => {
    const stats: Record<string, StudentStats> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉' || t.name === '寵物畫') return;

      const realName = normalizeName(t.name);
      if (!stats[realName]) {
        stats[realName] = { 
          name: realName, 
          totalSpent: 0, 
          courses: [], 
          lastActive: '',
          transactionCount: 0 
        };
      }

      if (t.paid) stats[realName].totalSpent += t.amount;
      if (!stats[realName].courses.includes(t.course)) stats[realName].courses.push(t.course);
      if (t.date > stats[realName].lastActive) stats[realName].lastActive = t.date;
      stats[realName].transactionCount++;
    });
    return Object.values(stats).sort((a, b) => b.totalSpent - a.totalSpent);
  }, [transactions]);

  // --- AI Logic ---
  const runAiAnalysis = async () => {
    setIsAnalyzing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        你是一位專業的畫室顧問。請根據以下 Koala Art Studio 的經營數據，提供 3 點關鍵洞察與 1 個營運建議。
        數據概要：
        - 總營收: $${metrics.totalRev}
        - 活躍學員: ${metrics.studentCount}人
        - 平均客單價: $${Math.round(metrics.totalRev / (metrics.studentCount || 1))}
        - 熱門學員: ${studentStats.slice(0,3).map(s => s.name).join(', ')}
        - 待收帳款: $${metrics.unpaid}
        請以精簡、溫暖且專業的語氣回答。
      `;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text);
    } catch (err) {
      console.error(err);
      setAiAnalysis("分析暫時無法產生，請稍後再試。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- Handlers ---

  const handleSaveTx = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newTx: Transaction = {
      id: editingTx?.id || `tx_${Date.now()}`,
      date: formData.get('date') as string,
      name: formData.get('name') as string,
      course: formData.get('course') as string,
      amount: parseInt(formData.get('amount') as string) || 0,
      paid: formData.get('status') === 'true',
      year: (formData.get('date') as string).substring(0, 4) === '2026' ? '115' : '114'
    };

    if (editingTx) {
      setTransactions(prev => prev.map(t => t.id === editingTx.id ? newTx : t));
    } else {
      setTransactions(prev => [newTx, ...prev]);
    }
    setIsModalOpen(false);
    setEditingTx(null);
  };

  const exportCSV = () => {
    const headers = "日期,姓名,項目,金額,狀態\n";
    const rows = transactions.map(t => `${t.date},${t.name},${t.course},${t.amount},${t.paid ? '已付' : '未付'}`).join("\n");
    const blob = new Blob(["\uFEFF" + headers + rows], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = "KoalaArt_Finance_Backup.csv";
    link.click();
  };

  return (
    <div className="flex min-h-screen bg-[#F7F5F2]">
      {/* Sidebar */}
      <aside className="w-80 bg-white border-r border-black/5 p-10 flex flex-col hidden lg:flex">
        <div className="flex items-center gap-4 mb-16">
          <div className="w-14 h-14 bg-[#F7F5F2] rounded-2xl flex items-center justify-center text-3xl border-2 border-[#EBE5DE]">🐨</div>
          <div>
            <h1 className="font-serif text-xl font-bold text-[#38332E]">Koala Art</h1>
            <p className="text-[10px] tracking-[3px] text-[#857E75] uppercase font-bold mt-1">Management V16</p>
          </div>
        </div>

        <nav className="space-y-3 flex-1">
          <SidebarItem active={view === 'dashboard'} icon={LayoutDashboard} label="儀表板" onClick={() => setView('dashboard')} />
          <SidebarItem active={view === 'students'} icon={Users} label="學員管理" onClick={() => setView('students')} />
          <SidebarItem active={view === 'finance'} icon={Receipt} label="財務對帳" onClick={() => setView('finance')} />
          <SidebarItem active={false} icon={Settings} label="系統設定" onClick={() => {}} />
        </nav>

        <button 
          onClick={exportCSV}
          className="mt-auto flex items-center gap-3 text-[#857E75] hover:text-[#38332E] font-medium transition-colors p-4"
        >
          <Download size={18} />
          <span>導出數據備份</span>
        </button>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6 lg:p-16 overflow-y-auto max-h-screen">
        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
          <div>
            <h2 className="font-serif text-4xl font-bold text-[#38332E]">
              {view === 'dashboard' ? '營運總覽' : view === 'students' ? '學員檔案' : '財務流水帳'}
            </h2>
            <p className="text-[#857E75] mt-2">
              {new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' })}
            </p>
          </div>
          <button 
            onClick={() => { setEditingTx(null); setIsModalOpen(true); }}
            className="bg-[#38332E] text-white px-8 py-4 rounded-2xl flex items-center gap-3 shadow-lg hover:shadow-2xl transition-all active:scale-95 font-semibold"
          >
            <Plus size={20} />
            <span>新增帳目</span>
          </button>
        </header>

        {view === 'dashboard' && (
          <div className="space-y-12">
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
              <StatCard label="總入帳金額 (LTD)" value={`$${metrics.totalRev.toLocaleString()}`} sub="已結轉 114 年度營收" icon={TrendingUp} color="#BA7A56" />
              <StatCard label="活躍學員人頭數" value={`${metrics.studentCount}`} sub="排除系統項與委託案" icon={Users} color="#8A9A8A" />
              <StatCard label="待收帳款" value={`$${metrics.unpaid.toLocaleString()}`} sub="目前無預設欠款" icon={CreditCard} color="#D18C8C" />
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
              <div className="xl:col-span-2 bg-white rounded-[32px] p-10 shadow-sm border border-black/5">
                <div className="flex justify-between items-center mb-8">
                  <h3 className="text-xl font-bold text-[#38332E] flex items-center gap-3">
                    <Receipt size={22} className="text-[#BA7A56]" />
                    近期交易紀錄
                  </h3>
                  <button onClick={() => setView('finance')} className="text-[#857E75] text-sm hover:text-[#BA7A56] font-medium flex items-center gap-1">
                    查看全部 <ChevronRight size={14} />
                  </button>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="text-[#857E75] text-sm font-medium border-b border-[#F7F5F2]">
                        <th className="pb-4 font-medium">日期</th>
                        <th className="pb-4 font-medium">學員姓名</th>
                        <th className="pb-4 font-medium">課程項目</th>
                        <th className="pb-4 font-medium text-right">金額</th>
                        <th className="pb-4 font-medium text-right">狀態</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-[#F7F5F2]">
                      {transactions.filter(t => t.id !== 'sys_bal').slice(0, 6).map(t => (
                        <tr 
                          key={t.id} 
                          className="group cursor-pointer hover:bg-[#F7F5F2]/50 transition-colors"
                          onClick={() => { setEditingTx(t); setIsModalOpen(true); }}
                        >
                          <td className="py-5 text-sm text-[#857E75]">{t.date}</td>
                          <td className="py-5 font-semibold text-[#38332E]">{t.name}</td>
                          <td className="py-5 text-[#857E75]">{t.course}</td>
                          <td className="py-5 text-right font-bold text-[#38332E] font-num">${t.amount.toLocaleString()}</td>
                          <td className="py-5 text-right">
                            <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${t.paid ? 'bg-[#E8F5E9] text-[#388E3C]' : 'bg-[#FFEBEE] text-[#D32F2F]'}`}>
                              {t.paid ? 'Paid' : 'Unpaid'}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>

              <div className="bg-[#38332E] rounded-[32px] p-10 text-white shadow-2xl relative overflow-hidden flex flex-col">
                <div className="absolute top-0 right-0 p-8 opacity-10">
                  <Sparkles size={80} />
                </div>
                <h3 className="text-2xl font-serif font-bold mb-6 flex items-center gap-3">
                  <Sparkles size={24} className="text-[#BA7A56]" />
                  AI 經營助手
                </h3>
                <div className="flex-1 space-y-4 text-white/80 leading-relaxed min-h-[200px]">
                  {isAnalyzing ? (
                    <div className="flex flex-col items-center justify-center h-full gap-4">
                      <div className="w-8 h-8 border-2 border-[#BA7A56] border-t-transparent rounded-full animate-spin"></div>
                      <p className="text-sm font-medium">正在分析畫室數據...</p>
                    </div>
                  ) : aiAnalysis ? (
                    <div className="prose prose-invert prose-sm">
                      <p className="whitespace-pre-wrap">{aiAnalysis}</p>
                    </div>
                  ) : (
                    <p>點擊下方按鈕，讓 Gemini 分析您畫室目前的財務健康度與學員偏好。</p>
                  )}
                </div>
                <button 
                  onClick={runAiAnalysis}
                  disabled={isAnalyzing}
                  className="mt-8 bg-[#BA7A56] text-white py-4 rounded-2xl font-bold hover:bg-[#C88A66] transition-all flex items-center justify-center gap-2"
                >
                  <TrendingUp size={18} />
                  {aiAnalysis ? '重新生成分析' : '生成營運洞察'}
                </button>
              </div>
            </div>
          </div>
        )}

        {view === 'students' && (
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
            {studentStats.map((s, idx) => (
              <div key={s.name} className="bg-white p-8 rounded-[32px] shadow-sm border border-black/5 hover:shadow-xl transition-all group">
                <div className="flex justify-between items-start mb-6">
                  <div className="w-16 h-16 bg-[#F7F5F2] rounded-2xl flex items-center justify-center text-2xl font-bold text-[#BA7A56] border-2 border-[#EBE5DE] group-hover:scale-110 transition-transform">
                    {s.name[0]}
                  </div>
                  <div className="text-right">
                    <span className="text-[10px] uppercase tracking-widest text-[#C4C0BA] font-bold">Total LTV</span>
                    <h4 className="text-2xl font-bold text-[#38332E] font-num">${s.totalSpent.toLocaleString()}</h4>
                  </div>
                </div>
                <h3 className="text-xl font-bold text-[#38332E] mb-1">{s.name}</h3>
                <p className="text-sm text-[#857E75] mb-6 flex items-center gap-2">
                  <TrendingUp size={14} /> 已上過 {s.transactionCount} 堂課程
                </p>
                <div className="flex flex-wrap gap-2 mb-6">
                  {s.courses.map(c => (
                    <span key={c} className="bg-[#F7F5F2] text-[#857E75] px-3 py-1 rounded-lg text-xs font-medium">{c}</span>
                  ))}
                </div>
                <div className="pt-6 border-t border-[#F7F5F2] flex justify-between items-center text-xs">
                  <span className="text-[#C4C0BA]">最後活躍</span>
                  <span className="text-[#857E75] font-bold">{s.lastActive}</span>
                </div>
              </div>
            ))}
          </div>
        )}

        {view === 'finance' && (
          <div className="bg-white rounded-[40px] shadow-sm border border-black/5 overflow-hidden">
            <div className="p-10 border-b border-[#F7F5F2] flex justify-between items-center">
              <h3 className="text-2xl font-bold text-[#38332E]">完整財務清單</h3>
              <div className="flex gap-4">
                 {/* Filters could go here */}
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-[#F7F5F2]/50 text-[#857E75] text-xs font-bold uppercase tracking-widest">
                    <th className="px-10 py-6">交易日期</th>
                    <th className="px-6 py-6">學員姓名</th>
                    <th className="px-6 py-6">課程/項目</th>
                    <th className="px-6 py-6 text-right">交易金額</th>
                    <th className="px-6 py-6 text-right">入帳狀態</th>
                    <th className="px-10 py-6 text-right">操作</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-[#F7F5F2]">
                  {transactions.map(t => (
                    <tr key={t.id} className="hover:bg-[#F7F5F2]/30 transition-colors">
                      <td className="px-10 py-6 text-sm font-medium text-[#857E75]">{t.date}</td>
                      <td className="px-6 py-6">
                        <span className={`font-bold ${t.name === '系統結轉' ? 'text-[#BA7A56]' : 'text-[#38332E]'}`}>{t.name}</span>
                      </td>
                      <td className="px-6 py-6 text-[#857E75]">{t.course}</td>
                      <td className="px-6 py-6 text-right font-bold text-[#38332E]">${t.amount.toLocaleString()}</td>
                      <td className="px-6 py-6 text-right">
                        <span className={`px-4 py-1.5 rounded-xl text-[10px] font-bold uppercase tracking-wider ${t.paid ? 'bg-[#E8F5E9] text-[#388E3C]' : 'bg-[#FFEBEE] text-[#D32F2F]'}`}>
                          {t.paid ? 'Settled' : 'Pending'}
                        </span>
                      </td>
                      <td className="px-10 py-6 text-right">
                        <button 
                          onClick={() => { setEditingTx(t); setIsModalOpen(true); }}
                          className="text-[#BA7A56] hover:text-[#38332E] font-bold text-sm"
                        >
                          編輯
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-[#38332E]/40 backdrop-blur-md" onClick={() => setIsModalOpen(false)} />
          <div className="relative bg-white w-full max-w-lg rounded-[40px] shadow-2xl p-10 animate-in fade-in zoom-in duration-300">
            <h2 className="font-serif text-3xl font-bold text-[#38332E] mb-8">{editingTx ? '編輯帳目' : '新增帳目'}</h2>
            <form onSubmit={handleSaveTx} className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-[#857E75] uppercase tracking-widest">日期</label>
                  <input name="date" type="date" required defaultValue={editingTx?.date || new Date().toISOString().split('T')[0]} className="w-full bg-[#F7F5F2] border-0 rounded-2xl px-6 py-4 text-[#38332E] focus:ring-2 focus:ring-[#BA7A56]" />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-[#857E75] uppercase tracking-widest">狀態</label>
                  <select name="status" defaultValue={editingTx?.paid ? 'true' : 'false'} className="w-full bg-[#F7F5F2] border-0 rounded-2xl px-6 py-4 text-[#38332E] focus:ring-2 focus:ring-[#BA7A56]">
                    <option value="true">已繳費 (Settled)</option>
                    <option value="false">未繳費 (Pending)</option>
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-[#857E75] uppercase tracking-widest">學員姓名</label>
                <input name="name" type="text" placeholder="輸入姓名..." required defaultValue={editingTx?.name || ''} className="w-full bg-[#F7F5F2] border-0 rounded-2xl px-6 py-4 text-[#38332E] focus:ring-2 focus:ring-[#BA7A56]" />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-[#857E75] uppercase tracking-widest">課程項目</label>
                <input name="course" type="text" placeholder="例如：肌理畫、油畫..." required defaultValue={editingTx?.course || ''} className="w-full bg-[#F7F5F2] border-0 rounded-2xl px-6 py-4 text-[#38332E] focus:ring-2 focus:ring-[#BA7A56]" />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-[#857E75] uppercase tracking-widest">交易金額</label>
                <div className="relative">
                  <span className="absolute left-6 top-1/2 -translate-y-1/2 text-[#857E75] font-bold">$</span>
                  <input name="amount" type="number" placeholder="0" required defaultValue={editingTx?.amount || ''} className="w-full bg-[#F7F5F2] border-0 rounded-2xl pl-10 pr-6 py-4 text-[#38332E] focus:ring-2 focus:ring-[#BA7A56] font-num" />
                </div>
              </div>

              <div className="pt-6 flex flex-col gap-3">
                <button type="submit" className="w-full bg-[#38332E] text-white py-5 rounded-2xl font-bold shadow-xl hover:shadow-2xl transition-all active:scale-95">
                  確認儲存
                </button>
                {editingTx && (
                  <button 
                    type="button" 
                    onClick={() => {
                      if(confirm('確定刪除這筆交易嗎？')) {
                        setTransactions(prev => prev.filter(t => t.id !== editingTx.id));
                        setIsModalOpen(false);
                      }
                    }}
                    className="w-full text-[#D32F2F] font-bold py-4 hover:bg-red-50 rounded-2xl transition-all"
                  >
                    刪除此筆紀錄
                  </button>
                )}
                <button type="button" onClick={() => setIsModalOpen(false)} className="w-full text-[#857E75] font-bold py-4 hover:bg-[#F7F5F2] rounded-2xl transition-all">
                  取消返回
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Floating Action for Mobile */}
      <button 
        onClick={() => { setEditingTx(null); setIsModalOpen(true); }}
        className="fixed bottom-10 right-10 lg:hidden w-16 h-16 bg-[#38332E] text-white rounded-full flex items-center justify-center shadow-2xl z-50"
      >
        <Plus size={32} />
      </button>

      {/* Bottom Nav for Mobile */}
      <nav className="fixed bottom-0 left-0 w-full bg-white border-t border-black/5 flex justify-around p-4 lg:hidden z-40 backdrop-blur-lg bg-white/90">
        <button onClick={() => setView('dashboard')} className={`p-2 rounded-xl ${view === 'dashboard' ? 'text-[#BA7A56]' : 'text-[#857E75]'}`}><LayoutDashboard size={24} /></button>
        <button onClick={() => setView('students')} className={`p-2 rounded-xl ${view === 'students' ? 'text-[#BA7A56]' : 'text-[#857E75]'}`}><Users size={24} /></button>
        <button onClick={() => setView('finance')} className={`p-2 rounded-xl ${view === 'finance' ? 'text-[#BA7A56]' : 'text-[#857E75]'}`}><Receipt size={24} /></button>
      </nav>
    </div>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Receipt, 
  Settings, 
  Plus, 
  ChevronRight, 
  ArrowUpRight,
  TrendingUp,
  CreditCard,
  Sparkles,
  Download,
  Search,
  Calendar,
  Filter,
  X
} from 'lucide-react';
import { Transaction, ViewState, StudentStats } from './types';
import { INITIAL_TRANSACTIONS, normalizeName, SYSTEM_COLORS } from './constants';
import { GoogleGenAI } from '@google/genai';

// --- Components ---

const SidebarItem = ({ active, icon: Icon, label, onClick }: { active: boolean; icon: any; label: string; onClick: () => void }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all duration-300 ${
      active 
      ? 'bg-[#38332E] text-white shadow-xl translate-x-1' 
      : 'text-[#857E75] hover:bg-white/50 hover:text-[#38332E]'
    }`}
  >
    <Icon size={20} />
    <span className="font-medium tracking-wide">{label}</span>
  </button>
);

const StatCard = ({ label, value, sub, icon: Icon, color }: { label: string; value: string; sub: string; icon: any; color: string }) => (
  <div className="bg-white p-8 rounded-[32px] shadow-sm hover:shadow-xl transition-all duration-500 group">
    <div className="flex justify-between items-start mb-6">
      <div className={`p-3 rounded-2xl ${color} bg-opacity-10 text-opacity-100`}>
        <Icon size={24} style={{ color }} />
      </div>
      <ArrowUpRight size={20} className="text-[#C4C0BA] group-hover:text-[#BA7A56] transition-colors" />
    </div>
    <div className="space-y-1">
      <p className="text-sm text-[#857E75] font-medium">{label}</p>
      <h3 className="text-4xl font-bold text-[#38332E] tracking-tight">{value}</h3>
      <p className="text-xs text-[#8FA895] flex items-center gap-1 mt-2">
        <TrendingUp size={12} /> {sub}
      </p>
    </div>
  </div>
);

// --- Main App ---

export default function App() {
  const [view, setView] = useState<ViewState>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('koala_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Filter States
  const [filterName, setFilterName] = useState('');
  const [filterCourse, setFilterCourse] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  useEffect(() => {
    localStorage.setItem('koala_transactions', JSON.stringify(transactions));
  }, [transactions]);

  // --- Data Logic ---

  const metrics = useMemo(() => {
    const totalRev = transactions.filter(t => t.paid).reduce((sum, t) => sum + t.amount, 0);
    const unpaid = transactions.filter(t => !t.paid).reduce((sum, t) => sum + t.amount, 0);

    const uniqueStudents = new Set<string>();
    transactions.forEach(t => {
      if (t.name !== '系統結轉' && t.name !== '寵物畫') {
        uniqueStudents.add(normalizeName(t.name));
      }
    });

    return { totalRev, unpaid, studentCount: uniqueStudents.size };
  }, [transactions]);

  const studentStats = useMemo(() => {
    const stats: Record<string, StudentStats> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉' || t.name === '寵物畫') return;

      const realName = normalizeName(t.name);
      if (!stats[realName]) {
        stats[realName] = { 
          name: realName, 
          totalSpent: 0, 
          courses: [], 
          lastActive: '',
          transactionCount: 0 
        };
      }

      if (t.paid) stats[realName].totalSpent += t.amount;
      if (!stats[realName].courses.includes(t.course)) stats[realName].courses.push(t.course);
      if (t.date > stats[realName].lastActive) stats[realName].lastActive = t.date;
      stats[realName].transactionCount++;
    });
    return Object.values(stats).sort((a, b) => b.totalSpent - a.totalSpent);
  }, [transactions]);

  const filteredFinance = useMemo(() => {
    return transactions.filter(t => {
      const matchesName = t.name.toLowerCase().includes(filterName.toLowerCase());
      const matchesCourse = t.course.toLowerCase().includes(filterCourse.toLowerCase());
      const matchesStartDate = startDate ? t.date >= startDate : true;
      const matchesEndDate = endDate ? t.date <= endDate : true;
      return matchesName && matchesCourse && matchesStartDate && matchesEndDate;
    });
  }, [transactions, filterName, filterCourse, startDate, endDate]);

  const resetFilters = () => {
    setFilterName('');
    setFilterCourse('');
    setStartDate('');
    setEndDate('');
  };

  // --- AI Logic ---
  const runAiAnalysis = async () => {
    setIsAnalyzing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        你是一位專業的畫室顧問。請根據以下 Koala Art Studio 的經營數據，提供 3 點關鍵洞察與 1 個營運建議。
        數據概要：
        - 總營收: $${metrics.totalRev}
        - 活躍學員: ${metrics.studentCount}人
        - 平均客單價: $${Math.round(metrics.totalRev / (metrics.studentCount || 1))}
        - 熱門學員: ${studentStats.slice(0,3).map(s => s.name).join(', ')}
        - 待收帳款: $${metrics.unpaid}
        請以精簡、溫暖且專業的語氣回答。
      `;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text);
    } catch (err) {
      console.error(err);
      setAiAnalysis("分析暫時無法產生，請稍後再試。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- Handlers ---

  const handleSaveTx = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newTx: Transaction = {
      id: editingTx?.id || `tx_${Date.now()}`,
      date: formData.get('date') as string,
      name: formData.get('name') as string,
      course: formData.get('course') as string,
      amount: parseInt(formData.get('amount') as string) || 0,
      paid: formData.get('status') === 'true',
      year: (formData.get('date') as string).substring(0, 4) === '2026' ? '115' : '114'
    };

    if (editingTx) {
      setTransactions(prev => prev.map(t => t.id === editingTx.id ? newTx : t));
    } else {
      setTransactions(prev => [newTx, ...prev]);
    }
    setIsModalOpen(false);
    setEditingTx(null);
  };

  const exportCSV = () => {
    const headers = "日期,姓名,項目,金額,狀態\n";
    const rows = filteredFinance.map(t => `${t.date},${t.name},${t.course},${t.amount},${t.paid ? '已付' : '未付'}`).join("\n");
    const blob = new Blob(["\uFEFF" + headers + rows], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `KoalaArt_Finance_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  return (
    <div className="flex min-h-screen bg-[#F7F5F2]">
      {/* Sidebar */}
      <aside className="w-80 bg-white border-r border-black/5 p-10 flex flex-col hidden lg:flex">
        <div className="flex items-center gap-4 mb-16">
          <div className="w-14 h-14 bg-[#F7F5F2] rounded-2xl flex items-center justify-center text-3xl border-2 border-[#EBE5DE]">🐨</div>
          <div>
            <h1 className="font-serif text-xl font-bold text-[#38332E]">Koala Art</h1>
            <p className="text-[10px] tracking-[3px] text-[#857E75] uppercase font-bold mt-1">Management V16</p>
          </div>
        </div>

        <nav className="space-y-3 flex-1">
          <SidebarItem active={view === 'dashboard'} icon={LayoutDashboard} label="儀表板" onClick={() => setView('dashboard')} />
          <SidebarItem active={view === 'students'} icon={Users} label="學員管理" onClick={() => setView('students')} />
          <SidebarItem active={view === 'finance'} icon={Receipt} label="財務對帳" onClick={() => setView('finance')} />
          <SidebarItem active={false} icon={Settings} label="系統設定" onClick={() => {}} />
        </nav>

        <button 
          onClick={exportCSV}
          className="mt-auto flex items-center gap-3 text-[#857E75] hover:text-[#38332E] font-medium transition-colors p-4"
        >
          <Download size={18} />
          <span>導出數據備份</span>
        </button>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6 lg:p-16 overflow-y-auto max-h-screen">
        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
          <div>
            <h2 className="font-serif text-4xl font-bold text-[#38332E]">
              {view === 'dashboard' ? '營運總覽' : view === 'students' ? '學員檔案' : '財務流水帳'}
            </h2>
            <p className="text-[#857E75] mt-2">
              {new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' })}
            </p>
          </div>
          <button 
            onClick={() => { setEditingTx(null); setIsModalOpen(true); }}
            className="bg-[#38332E] text-white px-8 py-4 rounded-2xl flex items-center gap-3 shadow-lg hover:shadow-2xl transition-all active:scale-95 font-semibold"
          >
            <Plus size={20} />
            <span>新增帳目</span>
          </button>
        </header>

        {view === 'dashboard' && (
          <div className="space-y-12">
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
              <StatCard label="總入帳金額 (LTD)" value={`$${metrics.totalRev.toLocaleString()}`} sub="已結轉 114 年度營收" icon={TrendingUp} color="#BA7A56" />
              <StatCard label="活躍學員人頭數" value={`${metrics.studentCount}`} sub="排除系統項與委託案" icon={Users} color="#8A9A8A" />
              <StatCard label="待收帳款" value={`$${metrics.unpaid.toLocaleString()}`} sub="目前無預設欠款" icon={CreditCard} color="#D18C8C" />
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
              <div className="xl:col-span-2 bg-white rounded-[32px] p-10 shadow-sm border border-black/5">
                <div className="flex justify-between items-center mb-8">
                  <h3 className="text-xl font-bold text-[#38332E] flex items-center gap-3">
                    <Receipt size={22} className="text-[#BA7A56]" />
                    近期交易紀錄
                  </h3>
                  <button onClick={() => setView('finance')} className="text-[#857E75] text-sm hover:text-[#BA7A56] font-medium flex items-center gap-1">
                    查看全部 <ChevronRight size={14} />
                  </button>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="text-[#857E75] text-sm font-medium border-b border-[#F7F5F2]">
                        <th className="pb-4 font-medium">日期</th>
                        <th className="pb-4 font-medium">學員姓名</th>
                        <th className="pb-4 font-medium">課程項目</th>
                        <th className="pb-4 font-medium text-right">金額</th>
                        <th className="pb-4 font-medium text-right">狀態</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-[#F7F5F2]">
                      {transactions.filter(t => t.id !== 'sys_bal').slice(0, 6).map(t => (
                        <tr 
                          key={t.id} 
                          className="group cursor-pointer hover:bg-[#F7F5F2]/50 transition-colors"
                          onClick={() => { setEditingTx(t); setIsModalOpen(true); }}
                        >
                          <td className="py-5 text-sm text-[#857E75]">{t.date}</td>
                          <td className="py-5 font-semibold text-[#38332E]">{t.name}</td>
                          <td className="py-5 text-[#857E75]">{t.course}</td>
                          <td className="py-5 text-right font-bold text-[#38332E] font-num">${t.amount.toLocaleString()}</td>
                          <td className="py-5 text-right">
                            <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${t.paid ? 'bg-[#E8F5E9] text-[#388E3C]' : 'bg-[#FFEBEE] text-[#D32F2F]'}`}>
                              {t.paid ? 'Paid' : 'Unpaid'}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>

              <div className="bg-[#38332E] rounded-[32px] p-10 text-white shadow-2xl relative overflow-hidden flex flex-col">
                <div className="absolute top-0 right-0 p-8 opacity-10">
                  <Sparkles size={80} />
                </div>
                <h3 className="text-2xl font-serif font-bold mb-6 flex items-center gap-3">
                  <Sparkles size={24} className="text-[#BA7A56]" />
                  AI 經營助手
                </h3>
                <div className="flex-1 space-y-4 text-white/80 leading-relaxed min-h-[200px]">
                  {isAnalyzing ? (
                    <div className="flex flex-col items-center justify-center h-full gap-4">
                      <div className="w-8 h-8 border-2 border-[#BA7A56] border-t-transparent rounded-full animate-spin"></div>
                      <p className="text-sm font-medium">正在分析畫室數據...</p>
                    </div>
                  ) : aiAnalysis ? (
                    <div className="prose prose-invert prose-sm">
                      <p className="whitespace-pre-wrap">{aiAnalysis}</p>
                    </div>
                  ) : (
                    <p>點擊下方按鈕，讓 Gemini 分析您畫室目前的財務健康度與學員偏好。</p>
                  )}
                </div>
                <button 
                  onClick={runAiAnalysis}
                  disabled={isAnalyzing}
                  className="mt-8 bg-[#BA7A56] text-white py-4 rounded-2xl font-bold hover:bg-[#C88A66] transition-all flex items-center justify-center gap-2"
                >
                  <TrendingUp size={18} />
                  {aiAnalysis ? '重新生成分析' : '生成營運洞察'}
                </button>
              </div>
            </div>
          </div>
        )}

        {view === 'students' && (
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
            {studentStats.map((s, idx) => (
              <div key={s.name} className="bg-white p-8 rounded-[32px] shadow-sm border border-black/5 hover:shadow-xl transition-all group">
                <div className="flex justify-between items-start mb-6">
                  <div className="w-16 h-16 bg-[#F7F5F2] rounded-2xl flex items-center justify-center text-2xl font-bold text-[#BA7A56] border-2 border-[#EBE5DE] group-hover:scale-110 transition-transform">
                    {s.name[0]}
                  </div>
                  <div className="text-right">
                    <span className="text-[10px] uppercase tracking-widest text-[#C4C0BA] font-bold">Total LTV</span>
                    <h4 className="text-2xl font-bold text-[#38332E] font-num">${s.totalSpent.toLocaleString()}</h4>
                  </div>
                </div>
                <h3 className="text-xl font-bold text-[#38332E] mb-1">{s.name}</h3>
                <p className="text-sm text-[#857E75] mb-6 flex items-center gap-2">
                  <TrendingUp size={14} /> 已上過 {s.transactionCount} 堂課程
                </p>
                <div className="flex flex-wrap gap-2 mb-6">
                  {s.courses.map(c => (
                    <span key={c} className="bg-[#F7F5F2] text-[#857E75] px-3 py-1 rounded-lg text-xs font-medium">{c}</span>
                  ))}
                </div>
                <div className="pt-6 border-t border-[#F7F5F2] flex justify-between items-center text-xs">
                  <span className="text-[#C4C0BA]">最後活躍</span>
                  <span className="text-[#857E75] font-bold">{s.lastActive}</span>
                </div>
              </div>
            ))}
          </div>
        )}

        {view === 'finance' && (
          <div className="space-y-6">
            {/* Filter Section */}
            <div className="bg-white p-8 rounded-[32px] shadow-sm border border-black/5 space-y-6">
              <div className="flex items-center gap-3 text-[#38332E] font-bold text-lg border-b border-[#F7F5F2] pb-4">
                <Filter size={20} className="text-[#BA7A56]" />
                數據篩選器
                {(filterName || filterCourse || startDate || endDate) && (
                  <button 
                    onClick={resetFilters}
                    className="ml-auto flex items-center gap-1 text-xs font-medium text-[#D18C8C] hover:text-[#D32F2F] transition-colors"
                  >
                    <X size={14} /> 清除全部
                  </button>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-[#857E75] uppercase tracking-[2px]">搜尋姓名</label>
                  <div className="relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-[#C4C0BA]" size={16} />
                    <input 
                      type="text" 
                      value={filterName}
                      onChange={(e) => setFilterName(e.target.value)}
                      placeholder="學員姓名..." 
                      className="w-full bg-[#F7F5F2] border-0 rounded-2xl pl-12 pr-4 py-3 text-sm focus:ring-2 focus:ring-[#BA7A56] transition-all"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-[#857E75] uppercase tracking-[2px]">搜尋課程</label>
                  <div className="relative">
                    <Sparkles className="absolute left-4 top-1/2 -translate-y-1/2 text-[#C4C0BA]" size={16} />
                    <input 
                      type="text" 
                      value={filterCourse}
                      onChange={(e) => setFilterCourse(e.target.value)}
                      placeholder="課程名稱..." 
                      className="w-full bg-[#F7F5F2] border-0 rounded-2xl pl-12 pr-4 py-3 text-sm focus:ring-2 focus:ring-[#BA7A56] transition-all"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-[#857E75] uppercase tracking-[2px]">起始日期</label>
                  <div className="relative">
                    <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-[#C4C0BA]" size={16} />
                    <input 
                      type="date" 
                      value={startDate}
                      onChange={(e) => setStartDate(e.target.value)}
                      className="w-full bg-[#F7F5F2] border-0 rounded-2xl pl-12 pr-4 py-3 text-sm focus:ring-2 focus:ring-[#BA7A56] transition-all"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-[#857E75] uppercase tracking-[2px]">結束日期</label>
                  <div className="relative">
                    <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-[#C4C0BA]" size={16} />
                    <input 
                      type="date" 
                      value={endDate}
                      onChange={(e) => setEndDate(e.target.value)}
                      className="w-full bg-[#F7F5F2] border-0 rounded-2xl pl-12 pr-4 py-3 text-sm focus:ring-2 focus:ring-[#BA7A56] transition-all"
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Table Section */}
            <div className="bg-white rounded-[40px] shadow-sm border border-black/5 overflow-hidden">
              <div className="p-10 border-b border-[#F7F5F2] flex justify-between items-center">
                <div>
                  <h3 className="text-2xl font-bold text-[#38332E]">完整財務清單</h3>
                  <p className="text-xs text-[#857E75] mt-1 font-medium">
                    顯示 {filteredFinance.length} 筆符合條件的紀錄
                  </p>
                </div>
                <button 
                  onClick={exportCSV}
                  className="flex items-center gap-2 text-sm font-bold text-[#BA7A56] hover:text-[#38332E] transition-colors"
                >
                  <Download size={18} /> 導出篩選結果
                </button>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="bg-[#F7F5F2]/50 text-[#857E75] text-xs font-bold uppercase tracking-widest">
                      <th className="px-10 py-6">交易日期</th>
                      <th className="px-6 py-6">學員姓名</th>
                      <th className="px-6 py-6">課程/項目</th>
                      <th className="px-6 py-6 text-right">交易金額</th>
                      <th className="px-6 py-6 text-right">入帳狀態</th>
                      <th className="px-10 py-6 text-right">操作</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-[#F7F5F2]">
                    {filteredFinance.length > 0 ? (
                      filteredFinance.map(t => (
                        <tr key={t.id} className="hover:bg-[#F7F5F2]/30 transition-colors">
                          <td className="px-10 py-6 text-sm font-medium text-[#857E75]">{t.date}</td>
                          <td className="px-6 py-6">
                            <span className={`font-bold ${t.name === '系統結轉' ? 'text-[#BA7A56]' : 'text-[#38332E]'}`}>{t.name}</span>
                          </td>
                          <td className="px-6 py-6 text-[#857E75]">{t.course}</td>
                          <td className="px-6 py-6 text-right font-bold text-[#38332E]">${t.amount.toLocaleString()}</td>
                          <td className="px-6 py-6 text-right">
                            <span className={`px-4 py-1.5 rounded-xl text-[10px] font-bold uppercase tracking-wider ${t.paid ? 'bg-[#E8F5E9] text-[#388E3C]' : 'bg-[#FFEBEE] text-[#D32F2F]'}`}>
                              {t.paid ? 'Settled' : 'Pending'}
                            </span>
                          </td>
                          <td className="px-10 py-6 text-right">
                            <button 
                              onClick={() => { setEditingTx(t); setIsModalOpen(true); }}
                              className="text-[#BA7A56] hover:text-[#38332E] font-bold text-sm"
                            >
                              編輯
                            </button>
                          </td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan={6} className="px-10 py-20 text-center">
                          <div className="flex flex-col items-center gap-4 text-[#C4C0BA]">
                            <Search size={48} className="opacity-20" />
                            <p className="font-medium">找不到符合條件的帳目紀錄</p>
                            <button onClick={resetFilters} className="text-[#BA7A56] text-sm font-bold underline decoration-dotted underline-offset-4">重設篩選條件</button>
                          </div>
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-[#38332E]/40 backdrop-blur-md" onClick={() => setIsModalOpen(false)} />
          <div className="relative bg-white w-full max-w-lg rounded-[40px] shadow-2xl p-10 animate-in fade-in zoom-in duration-300">
            <h2 className="font-serif text-3xl font-bold text-[#38332E] mb-8">{editingTx ? '編輯帳目' : '新增帳目'}</h2>
            <form onSubmit={handleSaveTx} className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-[#857E75] uppercase tracking-widest">日期</label>
                  <input name="date" type="date" required defaultValue={editingTx?.date || new Date().toISOString().split('T')[0]} className="w-full bg-[#F7F5F2] border-0 rounded-2xl px-6 py-4 text-[#38332E] focus:ring-2 focus:ring-[#BA7A56]" />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-[#857E75] uppercase tracking-widest">狀態</label>
                  <select name="status" defaultValue={editingTx?.paid ? 'true' : 'false'} className="w-full bg-[#F7F5F2] border-0 rounded-2xl px-6 py-4 text-[#38332E] focus:ring-2 focus:ring-[#BA7A56]">
                    <option value="true">已繳費 (Settled)</option>
                    <option value="false">未繳費 (Pending)</option>
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-[#857E75] uppercase tracking-widest">學員姓名</label>
                <input name="name" type="text" placeholder="輸入姓名..." required defaultValue={editingTx?.name || ''} className="w-full bg-[#F7F5F2] border-0 rounded-2xl px-6 py-4 text-[#38332E] focus:ring-2 focus:ring-[#BA7A56]" />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-[#857E75] uppercase tracking-widest">課程項目</label>
                <input name="course" type="text" placeholder="例如：肌理畫、油畫..." required defaultValue={editingTx?.course || ''} className="w-full bg-[#F7F5F2] border-0 rounded-2xl px-6 py-4 text-[#38332E] focus:ring-2 focus:ring-[#BA7A56]" />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-[#857E75] uppercase tracking-widest">交易金額</label>
                <div className="relative">
                  <span className="absolute left-6 top-1/2 -translate-y-1/2 text-[#857E75] font-bold">$</span>
                  <input name="amount" type="number" placeholder="0" required defaultValue={editingTx?.amount || ''} className="w-full bg-[#F7F5F2] border-0 rounded-2xl pl-10 pr-6 py-4 text-[#38332E] focus:ring-2 focus:ring-[#BA7A56] font-num" />
                </div>
              </div>

              <div className="pt-6 flex flex-col gap-3">
                <button type="submit" className="w-full bg-[#38332E] text-white py-5 rounded-2xl font-bold shadow-xl hover:shadow-2xl transition-all active:scale-95">
                  確認儲存
                </button>
                {editingTx && (
                  <button 
                    type="button" 
                    onClick={() => {
                      if(confirm('確定刪除這筆交易嗎？')) {
                        setTransactions(prev => prev.filter(t => t.id !== editingTx.id));
                        setIsModalOpen(false);
                      }
                    }}
                    className="w-full text-[#D32F2F] font-bold py-4 hover:bg-red-50 rounded-2xl transition-all"
                  >
                    刪除此筆紀錄
                  </button>
                )}
                <button type="button" onClick={() => setIsModalOpen(false)} className="w-full text-[#857E75] font-bold py-4 hover:bg-[#F7F5F2] rounded-2xl transition-all">
                  取消返回
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Floating Action for Mobile */}
      <button 
        onClick={() => { setEditingTx(null); setIsModalOpen(true); }}
        className="fixed bottom-24 right-6 lg:hidden w-16 h-16 bg-[#38332E] text-white rounded-full flex items-center justify-center shadow-2xl z-50"
      >
        <Plus size={32} />
      </button>

      {/* Bottom Nav for Mobile */}
      <nav className="fixed bottom-0 left-0 w-full bg-white border-t border-black/5 flex justify-around p-4 lg:hidden z-40 backdrop-blur-lg bg-white/90">
        <button onClick={() => setView('dashboard')} className={`p-2 rounded-xl ${view === 'dashboard' ? 'text-[#BA7A56]' : 'text-[#857E75]'}`}><LayoutDashboard size={24} /></button>
        <button onClick={() => setView('students')} className={`p-2 rounded-xl ${view === 'students' ? 'text-[#BA7A56]' : 'text-[#857E75]'}`}><Users size={24} /></button>
        <button onClick={() => setView('finance')} className={`p-2 rounded-xl ${view === 'finance' ? 'text-[#BA7A56]' : 'text-[#857E75]'}`}><Receipt size={24} /></button>
      </nav>
    </div>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Receipt, 
  Settings, 
  Plus, 
  ChevronRight, 
  ArrowUpRight,
  TrendingUp,
  CreditCard,
  Sparkles,
  Download,
  Search,
  Calendar,
  Filter,
  X,
  Clock
} from 'lucide-react';
import { Transaction, ViewState, StudentStats } from './types';
import { INITIAL_TRANSACTIONS, normalizeName, SYSTEM_COLORS } from './constants';
import { GoogleGenAI } from '@google/genai';

// --- Components ---

const SidebarItem = ({ active, icon: Icon, label, onClick }: { active: boolean; icon: any; label: string; onClick: () => void }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all duration-300 ${
      active 
      ? 'bg-[#38332E] text-white shadow-xl translate-x-1' 
      : 'text-[#857E75] hover:bg-white/50 hover:text-[#38332E]'
    }`}
  >
    <Icon size={20} />
    <span className="font-medium tracking-wide">{label}</span>
  </button>
);

const StatCard = ({ label, value, sub, icon: Icon, color }: { label: string; value: string; sub: string; icon: any; color: string }) => (
  <div className="bg-white p-8 rounded-[32px] shadow-sm hover:shadow-xl transition-all duration-500 group">
    <div className="flex justify-between items-start mb-6">
      <div className={`p-3 rounded-2xl ${color} bg-opacity-10 text-opacity-100`}>
        <Icon size={24} style={{ color }} />
      </div>
      <ArrowUpRight size={20} className="text-[#C4C0BA] group-hover:text-[#BA7A56] transition-colors" />
    </div>
    <div className="space-y-1">
      <p className="text-sm text-[#857E75] font-medium">{label}</p>
      <h3 className="text-4xl font-bold text-[#38332E] tracking-tight">{value}</h3>
      <p className="text-xs text-[#8FA895] flex items-center gap-1 mt-2">
        <TrendingUp size={12} /> {sub}
      </p>
    </div>
  </div>
);

// --- Main App ---

export default function App() {
  const [view, setView] = useState<ViewState>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('koala_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Filter States
  const [filterName, setFilterName] = useState('');
  const [filterCourse, setFilterCourse] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  useEffect(() => {
    localStorage.setItem('koala_transactions', JSON.stringify(transactions));
  }, [transactions]);

  // --- Data Logic ---

  const metrics = useMemo(() => {
    const totalRev = transactions.filter(t => t.paid).reduce((sum, t) => sum + t.amount, 0);
    const unpaid = transactions.filter(t => !t.paid).reduce((sum, t) => sum + t.amount, 0);

    const uniqueStudents = new Set<string>();
    transactions.forEach(t => {
      if (t.name !== '系統結轉' && t.name !== '寵物畫') {
        uniqueStudents.add(normalizeName(t.name));
      }
    });

    return { totalRev, unpaid, studentCount: uniqueStudents.size };
  }, [transactions]);

  const studentStats = useMemo(() => {
    const stats: Record<string, StudentStats> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉' || t.name === '寵物畫') return;

      const realName = normalizeName(t.name);
      if (!stats[realName]) {
        stats[realName] = { 
          name: realName, 
          totalSpent: 0, 
          courses: [], 
          lastActive: '',
          transactionCount: 0 
        };
      }

      if (t.paid) stats[realName].totalSpent += t.amount;
      if (!stats[realName].courses.includes(t.course)) stats[realName].courses.push(t.course);
      if (t.date > stats[realName].lastActive) stats[realName].lastActive = t.date;
      stats[realName].transactionCount++;
    });
    return Object.values(stats).sort((a, b) => b.totalSpent - a.totalSpent);
  }, [transactions]);

  const filteredFinance = useMemo(() => {
    return transactions.filter(t => {
      const matchesName = t.name.toLowerCase().includes(filterName.toLowerCase());
      const matchesCourse = t.course.toLowerCase().includes(filterCourse.toLowerCase());
      const matchesStartDate = startDate ? t.date >= startDate : true;
      const matchesEndDate = endDate ? t.date <= endDate : true;
      return matchesName && matchesCourse && matchesStartDate && matchesEndDate;
    });
  }, [transactions, filterName, filterCourse, startDate, endDate]);

  const resetFilters = () => {
    setFilterName('');
    setFilterCourse('');
    setStartDate('');
    setEndDate('');
  };

  const setPresetRange = (range: 'thisMonth' | '114' | '115' | 'all') => {
    const now = new Date();
    if (range === 'thisMonth') {
      const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
      const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
      setStartDate(firstDay);
      setEndDate(lastDay);
    } else if (range === '114') {
      setStartDate('2025-01-01');
      setEndDate('2025-12-31');
    } else if (range === '115') {
      setStartDate('2026-01-01');
      setEndDate('2026-12-31');
    } else {
      setStartDate('');
      setEndDate('');
    }
  };

  // --- AI Logic ---
  const runAiAnalysis = async () => {
    setIsAnalyzing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        你是一位專業的畫室顧問。請根據以下 Koala Art Studio 的經營數據，提供 3 點關鍵洞察與 1 個營運建議。
        數據概要：
        - 總營收: $${metrics.totalRev}
        - 活躍學員: ${metrics.studentCount}人
        - 平均客單價: $${Math.round(metrics.totalRev / (metrics.studentCount || 1))}
        - 熱門學員: ${studentStats.slice(0,3).map(s => s.name).join(', ')}
        - 待收帳款: $${metrics.unpaid}
        請以精簡、溫暖且專業的語氣回答。
      `;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text);
    } catch (err) {
      console.error(err);
      setAiAnalysis("分析暫時無法產生，請稍後再試。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- Handlers ---

  const handleSaveTx = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const dateStr = formData.get('date') as string;
    const yearPrefix = dateStr.substring(0, 4);

    const newTx: Transaction = {
      id: editingTx?.id || `tx_${Date.now()}`,
      date: dateStr,
      name: formData.get('name') as string,
      course: formData.get('course') as string,
      amount: parseInt(formData.get('amount') as string) || 0,
      paid: formData.get('status') === 'true',
      year: yearPrefix === '2026' ? '115' : yearPrefix === '2025' ? '114' : '113'
    };

    if (editingTx) {
      setTransactions(prev => prev.map(t => t.id === editingTx.id ? newTx : t));
    } else {
      setTransactions(prev => [newTx, ...prev]);
    }
    setIsModalOpen(false);
    setEditingTx(null);
  };

  const exportCSV = () => {
    const headers = "日期,姓名,項目,金額,狀態\n";
    const rows = filteredFinance.map(t => `${t.date},${t.name},${t.course},${t.amount},${t.paid ? '已付' : '未付'}`).join("\n");
    const blob = new Blob(["\uFEFF" + headers + rows], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `KoalaArt_Finance_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  return (
    <div className="flex min-h-screen bg-[#F7F5F2]">
      {/* Sidebar */}
      <aside className="w-80 bg-white border-r border-black/5 p-10 flex flex-col hidden lg:flex">
        <div className="flex items-center gap-4 mb-16">
          <div className="w-14 h-14 bg-[#F7F5F2] rounded-2xl flex items-center justify-center text-3xl border-2 border-[#EBE5DE]">🐨</div>
          <div>
            <h1 className="font-serif text-xl font-bold text-[#38332E]">Koala Art</h1>
            <p className="text-[10px] tracking-[3px] text-[#857E75] uppercase font-bold mt-1">Management V16</p>
          </div>
        </div>

        <nav className="space-y-3 flex-1">
          <SidebarItem active={view === 'dashboard'} icon={LayoutDashboard} label="儀表板" onClick={() => setView('dashboard')} />
          <SidebarItem active={view === 'students'} icon={Users} label="學員管理" onClick={() => setView('students')} />
          <SidebarItem active={view === 'finance'} icon={Receipt} label="財務對帳" onClick={() => setView('finance')} />
          <SidebarItem active={false} icon={Settings} label="系統設定" onClick={() => {}} />
        </nav>

        <button 
          onClick={exportCSV}
          className="mt-auto flex items-center gap-3 text-[#857E75] hover:text-[#38332E] font-medium transition-colors p-4"
        >
          <Download size={18} />
          <span>導出數據備份</span>
        </button>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6 lg:p-16 overflow-y-auto max-h-screen">
        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
          <div>
            <h2 className="font-serif text-4xl font-bold text-[#38332E]">
              {view === 'dashboard' ? '營運總覽' : view === 'students' ? '學員檔案' : '財務流水帳'}
            </h2>
            <p className="text-[#857E75] mt-2">
              {new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' })}
            </p>
          </div>
          <button 
            onClick={() => { setEditingTx(null); setIsModalOpen(true); }}
            className="bg-[#38332E] text-white px-8 py-4 rounded-2xl flex items-center gap-3 shadow-lg hover:shadow-2xl transition-all active:scale-95 font-semibold"
          >
            <Plus size={20} />
            <span>新增帳目</span>
          </button>
        </header>

        {view === 'dashboard' && (
          <div className="space-y-12">
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
              <StatCard label="總入帳金額 (LTD)" value={`$${metrics.totalRev.toLocaleString()}`} sub="已結轉 114 年度營收" icon={TrendingUp} color="#BA7A56" />
              <StatCard label="活躍學員人頭數" value={`${metrics.studentCount}`} sub="排除系統項與委託案" icon={Users} color="#8A9A8A" />
              <StatCard label="待收帳款" value={`$${metrics.unpaid.toLocaleString()}`} sub="目前無預設欠款" icon={CreditCard} color="#D18C8C" />
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
              <div className="xl:col-span-2 bg-white rounded-[32px] p-10 shadow-sm border border-black/5">
                <div className="flex justify-between items-center mb-8">
                  <h3 className="text-xl font-bold text-[#38332E] flex items-center gap-3">
                    <Receipt size={22} className="text-[#BA7A56]" />
                    近期交易紀錄
                  </h3>
                  <button onClick={() => setView('finance')} className="text-[#857E75] text-sm hover:text-[#BA7A56] font-medium flex items-center gap-1">
                    查看全部 <ChevronRight size={14} />
                  </button>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="text-[#857E75] text-sm font-medium border-b border-[#F7F5F2]">
                        <th className="pb-4 font-medium">日期</th>
                        <th className="pb-4 font-medium">學員姓名</th>
                        <th className="pb-4 font-medium">課程項目</th>
                        <th className="pb-4 font-medium text-right">金額</th>
                        <th className="pb-4 font-medium text-right">狀態</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-[#F7F5F2]">
                      {transactions.filter(t => t.id !== 'sys_bal').slice(0, 6).map(t => (
                        <tr 
                          key={t.id} 
                          className="group cursor-pointer hover:bg-[#F7F5F2]/50 transition-colors"
                          onClick={() => { setEditingTx(t); setIsModalOpen(true); }}
                        >
                          <td className="py-5 text-sm text-[#857E75]">{t.date}</td>
                          <td className="py-5 font-semibold text-[#38332E]">{t.name}</td>
                          <td className="py-5 text-[#857E75]">{t.course}</td>
                          <td className="py-5 text-right font-bold text-[#38332E] font-num">${t.amount.toLocaleString()}</td>
                          <td className="py-5 text-right">
                            <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${t.paid ? 'bg-[#E8F5E9] text-[#388E3C]' : 'bg-[#FFEBEE] text-[#D32F2F]'}`}>
                              {t.paid ? 'Paid' : 'Unpaid'}
                            </span>
                          </td>
