  const [quote] = useState(() => ART_QUOTES[Math.floor(Math.random() * ART_QUOTES.length)]);

  // Filter States
  const [filterName, setFilterName] = useState('');
  const [filterCourse, setFilterCourse] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  useEffect(() => {
    localStorage.setItem('koala_transactions', JSON.stringify(transactions));
  }, [transactions]);

  // --- Data Logic ---

  const metrics = useMemo(() => {
    const totalRev = transactions.filter(t => t.paid).reduce((sum, t) => sum + t.amount, 0);
    const unpaid = transactions.filter(t => !t.paid).reduce((sum, t) => sum + t.amount, 0);

    const uniqueStudents = new Set<string>();
    transactions.forEach(t => {
      if (t.name !== '系統結轉' && t.name !== '寵物畫') {
        uniqueStudents.add(normalizeName(t.name));
      }
    });

    // Monthly breakdown for simplified chart
    const monthMap: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.paid) {
        const month = t.date.substring(0, 7);
        monthMap[month] = (monthMap[month] || 0) + t.amount;
      }
    });
    const last6Months = Object.entries(monthMap)
      .sort((a, b) => b[0].localeCompare(a[0]))
      .slice(0, 6)
      .reverse();

    // Course category breakdown
    const categoryMap: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉') return;
      categoryMap[t.course] = (categoryMap[t.course] || 0) + 1;
    });
    const topCategories = Object.entries(categoryMap)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 4);

    return { totalRev, unpaid, studentCount: uniqueStudents.size, last6Months, topCategories };
  }, [transactions]);

  const studentStats = useMemo(() => {
    const stats: Record<string, StudentStats> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉' || t.name === '寵物畫') return;

      const realName = normalizeName(t.name);
      if (!stats[realName]) {
        stats[realName] = { 
          name: realName, 
          totalSpent: 0, 
          courses: [], 
          lastActive: '',
          transactionCount: 0 
        };
      }

      if (t.paid) stats[realName].totalSpent += t.amount;
      if (!stats[realName].courses.includes(t.course)) stats[realName].courses.push(t.course);
      if (t.date > stats[realName].lastActive) stats[realName].lastActive = t.date;
      stats[realName].transactionCount++;
    });
    return Object.values(stats).sort((a, b) => b.totalSpent - a.totalSpent);
  }, [transactions]);

  const filteredFinance = useMemo(() => {
    return transactions.filter(t => {
      const matchesName = t.name.toLowerCase().includes(filterName.toLowerCase());
      const matchesCourse = t.course.toLowerCase().includes(filterCourse.toLowerCase());
      const matchesStartDate = startDate ? t.date >= startDate : true;
      const matchesEndDate = endDate ? t.date <= endDate : true;
      return matchesName && matchesCourse && matchesStartDate && matchesEndDate;
    });
  }, [transactions, filterName, filterCourse, startDate, endDate]);

  const resetFilters = () => {
    setFilterName('');
    setFilterCourse('');
    setStartDate('');
    setEndDate('');
  };

  const setPresetRange = (range: 'thisMonth' | '114' | '115' | 'all') => {
    const now = new Date();
    if (range === 'thisMonth') {
      const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
      const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
      setStartDate(firstDay);
      setEndDate(lastDay);
    } else if (range === '114') {
      setStartDate('2025-01-01');
      setEndDate('2025-12-31');
    } else if (range === '115') {
      setStartDate('2026-01-01');
      setEndDate('2026-12-31');
    } else {
      setStartDate('');
      setEndDate('');
    }
  };

  // --- AI Logic ---
  const runAiAnalysis = async () => {
    setIsAnalyzing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        你是一位專業的畫室顧問。請根據以下 Koala Art Studio 的經營數據，提供 3 點關鍵洞察與 1 個營運建議。
        數據概要：
        - 總營收: $${metrics.totalRev}
        - 活躍學員: ${metrics.studentCount}人
        - 平均客單價: $${Math.round(metrics.totalRev / (metrics.studentCount || 1))}
        - 熱門學員: ${studentStats.slice(0,3).map(s => s.name).join(', ')}
        - 待收帳款: $${metrics.unpaid}
        請以精簡、溫暖且專業的語氣回答。
      `;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text);
    } catch (err) {
      console.error(err);
      setAiAnalysis("分析暫時無法產生，請稍後再試。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- Handlers ---

  const handleSaveTx = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const dateStr = formData.get('date') as string;
    const yearPrefix = dateStr.substring(0, 4);

    const newTx: Transaction = {
      id: editingTx?.id || `tx_${Date.now()}`,
      date: dateStr,
      name: formData.get('name') as string,
      course: formData.get('course') as string,
      amount: parseInt(formData.get('amount') as string) || 0,
      paid: formData.get('status') === 'true',
      year: yearPrefix === '2026' ? '115' : yearPrefix === '2025' ? '114' : '113'
    };

    if (editingTx) {
      setTransactions(prev => prev.map(t => t.id === editingTx.id ? newTx : t));
    } else {
      setTransactions(prev => [newTx, ...prev]);
    }
    setIsModalOpen(false);
    setEditingTx(null);
  };

  const exportCSV = () => {
    const headers = "日期,姓名,項目,金額,狀態\n";
    const rows = filteredFinance.map(t => `${t.date},${t.name},${t.course},${t.amount},${t.paid ? '已付' : '未付'}`).join("\n");
    const blob = new Blob(["\uFEFF" + headers + rows], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `KoalaArt_Finance_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  return (
    <div className="flex min-h-screen bg-[#F7F5F2]">
      {/* Sidebar */}
      <aside className="w-80 bg-white border-r border-black/5 p-10 flex flex-col hidden lg:flex">
        <div className="flex items-center gap-4 mb-16">
          <div className="w-14 h-14 bg-[#F7F5F2] rounded-2xl flex items-center justify-center text-3xl border-2 border-[#EBE5DE]">🐨</div>
          <div>
            <h1 className="font-serif text-xl font-bold text-[#38332E]">Koala Art</h1>
            <p className="text-[10px] tracking-[3px] text-[#857E75] uppercase font-bold mt-1">Studio V16.2</p>
          </div>
        </div>

        <nav className="space-y-3 flex-1">
          <SidebarItem active={view === 'dashboard'} icon={LayoutDashboard} label="儀表板總覽" onClick={() => setView('dashboard')} />
          <SidebarItem active={view === 'students'} icon={Users} label="學員檔案庫" onClick={() => setView('students')} />
          <SidebarItem active={view === 'finance'} icon={Receipt} label="財務對帳單" onClick={() => setView('finance')} />
          <SidebarItem active={false} icon={Palette} label="課室與材料" onClick={() => {}} />
          <SidebarItem active={false} icon={Settings} label="系統偏好" onClick={() => {}} />
        </nav>

        <div className="mt-auto space-y-6">
          <div className="bg-[#F7F5F2] p-6 rounded-[24px] border border-[#EBE5DE]">
             <Quote size={20} className="text-[#BA7A56] mb-3 opacity-50" />
             <p className="text-sm font-serif italic text-[#38332E] leading-relaxed">「{quote.text}」</p>
             <p className="text-[10px] font-bold text-[#857E75] mt-3 uppercase tracking-widest">— {quote.author}</p>
          </div>
          <button 
            onClick={exportCSV}
            className="w-full flex items-center gap-3 text-[#C4C0BA] hover:text-[#38332E] font-medium transition-colors px-4 text-xs"
          >
            <Download size={14} />
            <span>匯出全站數據備份</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6 lg:p-16 overflow-y-auto max-h-screen">
        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
          <div>
            <h2 className="font-serif text-4xl font-bold text-[#38332E]">
              {view === 'dashboard' ? '歡迎回來，Wen' : view === 'students' ? '學員檔案庫' : '財務流水對帳'}
            </h2>
            <div className="flex items-center gap-2 text-[#857E75] mt-3 text-sm font-medium">
              <CalendarDays size={14} className="text-[#BA7A56]" />
              {new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' })}
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => { setEditingTx(null); setIsModalOpen(true); }}
              className="bg-[#38332E] text-white px-8 py-4 rounded-2xl flex items-center gap-3 shadow-lg hover:shadow-2xl transition-all active:scale-95 font-semibold group"
            >
              <Plus size={20} className="group-hover:rotate-90 transition-transform" />
              <span>快速入帳</span>
            </button>
          </div>
        </header>

        {view === 'dashboard' && (
          <div className="space-y-10">
            {/* Top Metrics Bento */}
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
              <StatCard label="累計實收營收" value={`$${metrics.totalRev.toLocaleString()}`} sub="包含歷史結轉 114 年度" icon={TrendingUp} color="#BA7A56" />
              <StatCard label="畫室學員總數" value={`${metrics.studentCount}`} sub="已排除系統項與單次委託" icon={Users} color="#8A9A8A" />
              <StatCard label="待結清帳款" value={`$${metrics.unpaid.toLocaleString()}`} sub="目前財務狀態優良" icon={CreditCard} color="#D18C8C" />
            </div>

            {/* Middle Section Bento */}
            <div className="grid grid-cols-1 xl:grid-cols-12 gap-8">
              {/* Revenue Trend Chart Visual */}
              <div className="xl:col-span-8 bg-white rounded-[40px] p-10 shadow-sm border border-black/5">
                <div className="flex justify-between items-center mb-10">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-[#BA7A56]/10 rounded-xl flex items-center justify-center text-[#BA7A56]">
                      <TrendingUp size={20} />
                    </div>
                    <div>
                      <h3 className="text-xl font-bold text-[#38332E]">月度營收趨勢</h3>
                      <p className="text-xs text-[#857E75] mt-0.5">過去六個月的成長變化</p>
                    </div>
                  </div>
                  <div className="text-xs font-bold text-[#BA7A56] bg-[#BA7A56]/5 px-3 py-1.5 rounded-lg">Growth: +12.5%</div>
                </div>

                <div className="h-[240px] flex items-end justify-between px-4 gap-4">
                  {metrics.last6Months.map(([month, amount]) => (
                    <div key={month} className="flex-1 flex flex-col items-center group">
                      <div className="relative w-full flex flex-col items-center">
                        <div 
                          className="w-full max-w-[40px] bg-[#F7F5F2] rounded-t-2xl transition-all duration-1000 group-hover:bg-[#BA7A56]"
                          style={{ height: `${(amount / (Math.max(...metrics.last6Months.map(m => m[1])) || 1)) * 180}px` }}
                        >
                          <div className="absolute -top-10 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-opacity bg-[#38332E] text-white text-[10px] px-2 py-1 rounded-lg whitespace-nowrap">
                            ${amount.toLocaleString()}
                          </div>
                        </div>
                      </div>
                      <span className="mt-4 text-[10px] font-bold text-[#C4C0BA] uppercase tracking-tighter">{month.split('-')[1]}月</span>
                    </div>
                  ))}
                  {metrics.last6Months.length === 0 && (
                     <div className="w-full h-full flex items-center justify-center text-[#C4C0BA] italic text-sm">暫無足夠月份數據</div>
                  )}
                </div>
              </div>

              {/* Course Distribution */}
              <div className="xl:col-span-4 bg-white rounded-[40px] p-10 shadow-sm border border-black/5 flex flex-col">
                <div className="flex items-center gap-3 mb-8">
                  <div className="w-10 h-10 bg-[#8A9A8A]/10 rounded-xl flex items-center justify-center text-[#8A9A8A]">
                    <PieChart size={20} />
                  </div>
                  <div>
                    <h3 className="text-xl font-bold text-[#38332E]">熱門課程佔比</h3>
                    <p className="text-xs text-[#857E75] mt-0.5">學員最感興趣的項目</p>
                  </div>
                </div>
                <div className="flex-1 space-y-6">
                  {metrics.topCategories.map(([category, count], idx) => (
                    <div key={category} className="space-y-2">
                      <div className="flex justify-between text-xs font-bold">
                        <span className="text-[#38332E]">{category}</span>
                        <span className="text-[#857E75]">{count} 人次</span>
                      </div>
                      <div className="h-2 bg-[#F7F5F2] rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-[#BA7A56] rounded-full transition-all duration-1000"
                          style={{ width: `${(count / (metrics.studentCount || 1)) * 100}%`, backgroundColor: idx % 2 === 0 ? '#BA7A56' : '#8A9A8A' }}
                        ></div>
                      </div>
                    </div>
                  ))}
                  {metrics.topCategories.length === 0 && (
                     <div className="w-full h-full flex items-center justify-center text-[#C4C0BA] italic text-sm pt-10">尚無課程數據</div>
                  )}
                </div>
              </div>
            </div>

            {/* Bottom Section Bento */}
            <div className="grid grid-cols-1 xl:grid-cols-12 gap-8">
              {/* Recent Activity */}
              <div className="xl:col-span-7 bg-white rounded-[40px] p-10 shadow-sm border border-black/5">
                <div className="flex justify-between items-center mb-8">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-[#38332E]/5 rounded-xl flex items-center justify-center text-[#38332E]">
                      <Clock size={20} />
                    </div>
                    <h3 className="text-xl font-bold text-[#38332E]">即時動態紀錄</h3>
                  </div>
                  <button onClick={() => setView('finance')} className="text-[#BA7A56] text-sm hover:underline font-bold flex items-center gap-1 transition-all">
                    進入帳簿 <ChevronRight size={14} />
                  </button>
                </div>
                <div className="space-y-1">
                  {transactions.filter(t => t.id !== 'sys_bal').slice(0, 5).map(t => (
                    <div 
                      key={t.id} 
                      className="group flex items-center justify-between p-4 rounded-2xl hover:bg-[#F7F5F2] transition-all cursor-pointer"
                      onClick={() => { setEditingTx(t); setIsModalOpen(true); }}
                    >
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-white rounded-xl shadow-sm border border-black/5 flex items-center justify-center font-bold text-[#BA7A56]">
                          {t.name[0]}
                        </div>
                        <div>
                          <p className="font-bold text-[#38332E]">{t.name}</p>
                          <p className="text-[10px] text-[#857E75] uppercase tracking-widest">{t.course}</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="font-bold text-[#38332E] font-num">${t.amount.toLocaleString()}</p>
                        <p className="text-[10px] text-[#C4C0BA]">{t.date}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* AI Insights & Alerts */}
              <div className="xl:col-span-5 flex flex-col gap-8">
                {/* AI Assistant */}
                <div className="bg-[#38332E] rounded-[40px] p-10 text-white shadow-2xl relative overflow-hidden flex-1 group">
                  <div className="absolute -bottom-10 -right-10 opacity-[0.05] group-hover:scale-125 transition-transform duration-1000">
                    <Sparkles size={240} />
                  </div>
                  <h3 className="text-2xl font-serif font-bold mb-6 flex items-center gap-3">
                    <Sparkles size={24} className="text-[#BA7A56] animate-pulse" />
                    畫室經營洞察
                  </h3>
                  <div className="space-y-4 text-white/70 leading-relaxed text-sm h-[180px] overflow-y-auto custom-scrollbar">
                    {isAnalyzing ? (
                      <div className="flex flex-col items-center justify-center h-full gap-4">
                        <div className="w-6 h-6 border-2 border-[#BA7A56] border-t-transparent rounded-full animate-spin"></div>
                        <p className="text-xs font-medium tracking-widest uppercase opacity-60">數據精算中...</p>
                      </div>
                    ) : aiAnalysis ? (
                      <p className="whitespace-pre-wrap">{aiAnalysis}</p>
                    ) : (
                      <p className="italic">「這裡將顯示由 Gemini 產生的經營建議，幫助您優化畫室的發展計畫與財務健康度。」</p>
                    )}
                  </div>
                  <button 
                    onClick={runAiAnalysis}
                    disabled={isAnalyzing}
                    className="mt-8 w-full bg-[#BA7A56] text-white py-4 rounded-2xl font-bold hover:bg-[#C88A66] transition-all flex items-center justify-center gap-3 shadow-xl active:scale-95"
                  >
                    <TrendingUp size={18} />
                    {aiAnalysis ? '刷新經營分析' : '即刻生成洞察'}
                  </button>
                </div>

                {/* Quick Alerts */}
                <div className="bg-white rounded-[40px] p-10 shadow-sm border border-black/5">
                  <h3 className="text-lg font-bold text-[#38332E] mb-6 flex items-center gap-3">
                    <Award size={20} className="text-[#BA7A56]" />
                    畫室成就與提醒
                  </h3>
                  <div className="space-y-4">
                    <div className="flex items-start gap-4 p-4 rounded-2xl bg-[#8A9A8A]/5 border border-[#8A9A8A]/10">
                      <div className="mt-1 w-2 h-2 bg-[#8A9A8A] rounded-full"></div>
                      <div>
                        <p className="text-sm font-bold text-[#38332E]">VIP 學員達成</p>
                        <p className="text-xs text-[#857E75] mt-1">鄭梅芬 已累計參與超過 5 堂課程，可考慮提供回饋優惠。</p>
                      </div>
                    </div>
                    <div className="flex items-start gap-4 p-4 rounded-2xl bg-[#BA7A56]/5 border border-[#BA7A56]/10">
                      <div className="mt-1 w-2 h-2 bg-[#BA7A56] rounded-full"></div>
                      <div>
                        <p className="text-sm font-bold text-[#38332E]">季度財務結轉</p>
                        <p className="text-xs text-[#857E75] mt-1">115 年度第一季營收即將彙整，請確認所有近期帳目。</p>
                      </div>
