        {view === 'students' && (
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
            {studentStats.map((s, idx) => (
              <div key={s.name} className="bg-white p-8 rounded-[32px] shadow-sm border border-black/5 hover:shadow-xl transition-all group">
                <div className="flex justify-between items-start mb-6">
                  <div className="w-16 h-16 bg-[#F7F5F2] rounded-2xl flex items-center justify-center text-2xl font-bold text-[#BA7A56] border-2 border-[#EBE5DE] group-hover:scale-110 transition-transform">
                    {s.name[0]}
                  </div>
                  <div className="text-right">
                    <span className="text-[10px] uppercase tracking-widest text-[#C4C0BA] font-bold">Total LTV</span>
                    <h4 className="text-2xl font-bold text-[#38332E] font-num">${s.totalSpent.toLocaleString()}</h4>
