                <div className="pt-6 border-t border-[#F7F5F2] flex justify-between items-center text-xs">
                  <span className="text-[#C4C0BA]">最後活躍時間</span>
                  <span className="text-[#857E75] font-bold">{s.lastActive}</span>
                </div>
              </div>
            ))}
          </div>
        )}

        {view === 'finance' && (
          <div className="space-y-8">
            {/* Advanced Filter Section */}
            <div className="bg-white p-10 rounded-[40px] shadow-sm border border-black/5 space-y-8">
              <div className="flex flex-wrap items-center justify-between gap-4 border-b border-[#F7F5F2] pb-6">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 bg-[#BA7A56]/10 rounded-xl flex items-center justify-center text-[#BA7A56]">
