import { INITIAL_TRANSACTIONS, normalizeName, SYSTEM_COLORS } from './constants';
import { GoogleGenAI } from '@google/genai';

// --- Constants & Artistic Metadata ---

const ART_QUOTES = [
  { text: "藝術並不是真理。藝術是能讓我們意識到真理的謊言。", author: "畢卡索" },
  { text: "我夢想著繪畫，我繪畫著夢想。", author: "梵谷" },
  { text: "每一種創作行為，首先都是一種破壞行為。", author: "畢卡索" },
  { text: "藝術不需要翻譯，它是一種心靈的共鳴。", author: "佚名" },
  { text: "色彩是我永恆的追求。", author: "莫內" },
  { text: "繪畫是詩，而詩是無形的繪畫。", author: "達文西" }
];

// --- Styled Components ---

