// --- Main Application ---

export default function App() {
  const [view, setView] = useState<ViewState>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('koala_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [quote] = useState(() => ART_QUOTES[Math.floor(Math.random() * ART_QUOTES.length)]);

  // Filter States
  const [filterName, setFilterName] = useState('');
  const [filterCourse, setFilterCourse] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  useEffect(() => {
    localStorage.setItem('koala_transactions', JSON.stringify(transactions));
  }, [transactions]);

  // --- Analytical Logic ---

  const analytics = useMemo(() => {
    const totalRev = transactions.filter(t => t.paid).reduce((sum, t) => sum + t.amount, 0);
    const unpaid = transactions.filter(t => !t.paid).reduce((sum, t) => sum + t.amount, 0);

    const uniqueStudents = new Set<string>();
    transactions.forEach(t => {
      if (t.name !== '系統結轉' && t.name !== '寵物畫') {
        uniqueStudents.add(normalizeName(t.name));
      }
    });

    // Monthly revenue trend (last 6 months)
    const monthMap: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.paid) {
        const month = t.date.substring(0, 7);
        monthMap[month] = (monthMap[month] || 0) + t.amount;
      }
    });
    const revenueHistory = Object.entries(monthMap)
      .sort((a, b) => b[0].localeCompare(a[0]))
      .slice(0, 6)
      .reverse();

    // Course popularity
    const courseMap: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉') return;
      courseMap[t.course] = (courseMap[t.course] || 0) + 1;
    });
    const topCourses = Object.entries(courseMap)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5);

    return { totalRev, unpaid, studentCount: uniqueStudents.size, revenueHistory, topCourses };
  }, [transactions]);

  const topStudents = useMemo(() => {
    const stats: Record<string, StudentStats> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉' || t.name === '寵物畫') return;
      const realName = normalizeName(t.name);
      if (!stats[realName]) {
        stats[realName] = { name: realName, totalSpent: 0, courses: [], lastActive: '', transactionCount: 0 };
      }
      if (t.paid) stats[realName].totalSpent += t.amount;
      if (!stats[realName].courses.includes(t.course)) stats[realName].courses.push(t.course);
      if (t.date > stats[realName].lastActive) stats[realName].lastActive = t.date;
      stats[realName].transactionCount++;
    });
    return Object.values(stats).sort((a, b) => b.totalSpent - a.totalSpent).slice(0, 4);
  }, [transactions]);

  const filteredFinance = useMemo(() => {
    return transactions.filter(t => {
      const matchesName = t.name.toLowerCase().includes(filterName.toLowerCase());
      const matchesCourse = t.course.toLowerCase().includes(filterCourse.toLowerCase());
      const matchesStartDate = startDate ? t.date >= startDate : true;
      const matchesEndDate = endDate ? t.date <= endDate : true;
      return matchesName && matchesCourse && matchesStartDate && matchesEndDate;
    });
  }, [transactions, filterName, filterCourse, startDate, endDate]);

  // --- Handlers ---

  const runAiConsultant = async () => {
    setIsAnalyzing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        角色：Koala Art Studio 專屬經營顧問 (Dr. Wen 的 AI 助手)
        場景：分析當前畫室數據，並提供具有文藝氣息與商業洞察的建議。
        數據：
        - 累計營收: $${analytics.totalRev}
        - 活跃學生數: ${analytics.studentCount} 位
        - 最受歡迎課程: ${analytics.topCourses.map(c => c[0]).join(', ')}
        - 待結清金額: $${analytics.unpaid}
        任務：請提供 3 點具有啟發性的經營點評與 1 個下季度的創意活動提議。使用繁體中文。
      `;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text);
    } catch (err) {
      setAiAnalysis("分析受阻，請確保網路穩定後重試。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSaveTx = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const dateStr = formData.get('date') as string;
