        <button onClick={() => setView('finance')} className={`flex flex-col items-center gap-1.5 transition-colors ${view === 'finance' ? 'text-[#BA7A56]' : 'text-[#C4C0BA]'}`}>
           <Receipt size={22} />
           <span className="text-[9px] font-bold uppercase tracking-widest">Ledger</span>
        </button>
      </nav>
    </div>
  );
}

