// --- Main Application ---

export default function App() {
  const [view, setView] = useState<ViewState>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('koala_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [quote] = useState(() => ART_QUOTES[Math.floor(Math.random() * ART_QUOTES.length)]);

  // Filter States
  const [filterName, setFilterName] = useState('');
  const [filterCourse, setFilterCourse] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  useEffect(() => {
    localStorage.setItem('koala_transactions', JSON.stringify(transactions));
  }, [transactions]);

  // --- Analytical Logic ---

  const analytics = useMemo(() => {
    const totalRev = transactions.filter(t => t.paid).reduce((sum, t) => sum + t.amount, 0);
    const unpaid = transactions.filter(t => !t.paid).reduce((sum, t) => sum + t.amount, 0);

    const uniqueStudents = new Set<string>();
    transactions.forEach(t => {
      if (t.name !== '系統結轉' && t.name !== '寵物畫') {
        uniqueStudents.add(normalizeName(t.name));
      }
    });

    // Monthly revenue trend (last 6 months)
    const monthMap: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.paid) {
        const month = t.date.substring(0, 7);
        monthMap[month] = (monthMap[month] || 0) + t.amount;
      }
    });
    const revenueHistory = Object.entries(monthMap)
      .sort((a, b) => b[0].localeCompare(a[0]))
      .slice(0, 6)
      .reverse();

    // Course popularity
    const courseMap: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉') return;
      courseMap[t.course] = (courseMap[t.course] || 0) + 1;
    });
    const topCourses = Object.entries(courseMap)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5);

    return { totalRev, unpaid, studentCount: uniqueStudents.size, revenueHistory, topCourses };
  }, [transactions]);

  const topStudents = useMemo(() => {
    const stats: Record<string, StudentStats> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉' || t.name === '寵物畫') return;
      const realName = normalizeName(t.name);
      if (!stats[realName]) {
        stats[realName] = { name: realName, totalSpent: 0, courses: [], lastActive: '', transactionCount: 0 };
      }
      if (t.paid) stats[realName].totalSpent += t.amount;
      if (!stats[realName].courses.includes(t.course)) stats[realName].courses.push(t.course);
      if (t.date > stats[realName].lastActive) stats[realName].lastActive = t.date;
      stats[realName].transactionCount++;
    });
    return Object.values(stats).sort((a, b) => b.totalSpent - a.totalSpent).slice(0, 4);
  }, [transactions]);

  const filteredFinance = useMemo(() => {
    return transactions.filter(t => {
      const matchesName = t.name.toLowerCase().includes(filterName.toLowerCase());
      const matchesCourse = t.course.toLowerCase().includes(filterCourse.toLowerCase());
      const matchesStartDate = startDate ? t.date >= startDate : true;
      const matchesEndDate = endDate ? t.date <= endDate : true;
      return matchesName && matchesCourse && matchesStartDate && matchesEndDate;
    });
  }, [transactions, filterName, filterCourse, startDate, endDate]);

  // --- Handlers ---

  // Fix: Use process.env.API_KEY directly as required
  const runAiConsultant = async () => {
    setIsAnalyzing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        角色：Koala Art Studio 專屬經營顧問 (Dr. Wen 的 AI 助手)
        場景：分析當前畫室數據，並提供具有文藝氣息與商業洞察的建議。
        數據：
        - 累計營收: $${analytics.totalRev}
        - 活跃學生數: ${analytics.studentCount} 位
        - 最受歡迎課程: ${analytics.topCourses.map(c => c[0]).join(', ')}
        - 待結清金額: $${analytics.unpaid}
        任務：請提供 3 點具有啟發性的經營點評與 1 個下季度的創意活動提議。使用繁體中文。
      `;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text || "目前顧問正在思考中，請稍候。");
    } catch (err) {
      setAiAnalysis("分析受阻，請確保網路穩定後重試。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSaveTx = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const dateStr = formData.get('date') as string;
    const yearPrefix = dateStr.substring(0, 4);
    const newTx: Transaction = {
      id: editingTx?.id || `tx_${Date.now()}`,
      date: dateStr,
      name: formData.get('name') as string,
      course: formData.get('course') as string,
      amount: parseInt(formData.get('amount') as string) || 0,
      paid: formData.get('status') === 'true',
      year: yearPrefix === '2026' ? '115' : yearPrefix === '2025' ? '114' : '113'
    };
    if (editingTx) {
      setTransactions(prev => prev.map(t => t.id === editingTx.id ? newTx : t));
    } else {
      setTransactions(prev => [newTx, ...prev]);
    }
    setIsModalOpen(false);
    setEditingTx(null);
  };

  const resetFilters = () => {
    setFilterName(''); setFilterCourse(''); setStartDate(''); setEndDate('');
  };

  // Fix: Added missing exportCSV function
  const exportCSV = () => {
    const headers = "日期,姓名,項目,金額,狀態,年份\n";
    const rows = transactions.map(t => 
      `${t.date},${t.name},${t.course},${t.amount},${t.paid ? '已付' : '未付'},${t.year}`
    ).join("\n");
    const blob = new Blob(["\ufeff" + headers + rows], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", `koala_finance_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="flex min-h-screen bg-[#F7F5F2] selection:bg-[#BA7A56]/20">
      {/* Sidebar - Desktop Only */}
      <aside className="w-80 bg-white/60 backdrop-blur-xl border-r border-black/[0.03] p-10 flex flex-col hidden lg:flex sticky top-0 h-screen">
        <div className="flex items-center gap-4 mb-20 group cursor-pointer">
          <div className="w-14 h-14 bg-[#38332E] rounded-3xl flex items-center justify-center text-3xl shadow-xl group-hover:rotate-12 transition-transform duration-500">🐨</div>
          <div>
            <h1 className="font-serif text-xl font-bold text-[#38332E] tracking-tight">Koala Art</h1>
            <p className="text-[10px] tracking-[4px] text-[#BA7A56] uppercase font-bold mt-1.5 opacity-80">Studio Hub</p>
          </div>
        </div>

        <nav className="space-y-4 flex-1">
          <SidebarItem active={view === 'dashboard'} icon={LayoutDashboard} label="儀表板總覽" onClick={() => setView('dashboard')} />
          <SidebarItem active={view === 'students'} icon={Users} label="學員檔案庫" onClick={() => setView('students')} />
          <SidebarItem active={view === 'finance'} icon={Receipt} label="財務對帳單" onClick={() => setView('finance')} />
          <SidebarItem active={false} icon={Palette} label="課室與排課" onClick={() => {}} />
          <SidebarItem active={false} icon={Settings} label="系統偏好" onClick={() => {}} />
        </nav>

        <div className="mt-auto space-y-8">
          <div className="relative group">
            <div className="absolute inset-0 bg-[#BA7A56]/5 rounded-[32px] blur-xl opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>
            <div className="relative bg-white border border-black/[0.03] p-8 rounded-[32px] shadow-sm">
              <Quote size={20} className="text-[#BA7A56] mb-4 opacity-40" />
              <p className="text-sm font-serif italic text-[#38332E] leading-relaxed line-clamp-4">「{quote.text}」</p>
              <div className="mt-5 pt-5 border-t border-[#F7F5F2] flex items-center justify-between">
                <span className="text-[10px] font-bold text-[#C4C0BA] uppercase tracking-widest">{quote.author}</span>
                <Heart size={12} className="text-[#D18C8C]" />
              </div>
            </div>
          </div>
          <button onClick={() => {}} className="w-full flex items-center gap-3 text-[#C4C0BA] hover:text-[#38332E] font-bold transition-all px-4 text-[10px] uppercase tracking-widest">
            <Download size={14} /> 導出完整備份
          </button>
        </div>
      </aside>

      {/* Main Container */}
      <main className="flex-1 p-6 lg:p-16 overflow-y-auto">
        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-16">
          <div className="space-y-2">
            <h2 className="font-serif text-5xl font-bold text-[#38332E] tracking-tighter">
              {view === 'dashboard' ? 'Studio Pulse' : view === 'students' ? 'Student Archives' : 'Financial Ledger'}
            </h2>
            <div className="flex items-center gap-3 text-[#857E75] text-xs font-semibold tracking-wide">
              <div className="w-1.5 h-1.5 bg-[#BA7A56] rounded-full"></div>
              {new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' })}
            </div>
          </div>
          <button 
            onClick={() => { setEditingTx(null); setIsModalOpen(true); }}
            className="bg-[#38332E] text-white px-10 py-5 rounded-[24px] flex items-center gap-3 shadow-[0_20px_40px_rgba(56,51,46,0.15)] hover:shadow-2xl hover:-translate-y-1 transition-all active:scale-95 font-bold group"
          >
            <Plus size={20} className="group-hover:rotate-90 transition-transform duration-500" />
            <span className="tracking-wide">新增營運帳目</span>
