              <BentoCard className="xl:col-span-8" title="營收成長脈絡" icon={Waves} action={<span className="text-[10px] font-bold text-[#BA7A56] bg-[#BA7A56]/5 px-3 py-1.5 rounded-lg tracking-widest uppercase">Growth +12%</span>}>
                <div className="h-64 flex items-end justify-between px-6 gap-6 pt-10">
                  {analytics.revenueHistory.map(([month, amount]) => (
                    <div key={month} className="flex-1 flex flex-col items-center group relative h-full justify-end">
                      <div className="w-full max-w-[50px] bg-[#F7F5F2] rounded-2xl relative overflow-hidden transition-all duration-700 group-hover:bg-[#38332E]/5" style={{ height: '100%' }}>
