            {/* Bottom Bento Grid */}
            <div className="grid grid-cols-1 xl:grid-cols-12 gap-8">
              {/* VIP Spotlight */}
              <BentoCard className="xl:col-span-4" title="學員影響力排行" icon={Award}>
