                    <option value="true">已繳費核銷 (Settled)</option>
                    <option value="false">待繳費 (Pending)</option>
                  </select>
                </div>
              </div>
              <div className="space-y-4">
                <label className="text-[10px] font-bold text-[#C4C0BA] uppercase tracking-widest block px-2">學員靈魂姓名</label>
                <input name="name" type="text" placeholder="輸入學員姓名..." required defaultValue={editingTx?.name || ''} className="w-full bg-[#FAF9F6] border-0 rounded-[24px] px-8 py-6 text-[#2D2926] focus:ring-4 focus:ring-[#BA7A56]/10 text-sm font-bold" />
              </div>
              <div className="space-y-4">
                <label className="text-[10px] font-bold text-[#C4C0BA] uppercase tracking-widest block px-2">課程名稱 / 媒材類別</label>
                <input name="course" type="text" placeholder="例如：肌理畫、油畫工作坊..." required defaultValue={editingTx?.course || ''} className="w-full bg-[#FAF9F6] border-0 rounded-[24px] px-8 py-6 text-[#2D2926] focus:ring-4 focus:ring-[#BA7A56]/10 text-sm font-bold" />
              </div>
              <div className="space-y-4">
                <label className="text-[10px] font-bold text-[#C4C0BA] uppercase tracking-widest block px-2">交易實收金額 (NTD)</label>
                <div className="relative">
                  <span className="absolute left-8 top-1/2 -translate-y-1/2 text-[#C4C0BA] font-serif font-bold text-2xl">$</span>
                  <input name="amount" type="number" placeholder="0" required defaultValue={editingTx?.amount || ''} className="w-full bg-[#FAF9F6] border-0 rounded-[24px] pl-16 pr-8 py-8 text-[#2D2926] focus:ring-4 focus:ring-[#BA7A56]/10 font-serif font-bold text-4xl" />
                </div>
              </div>
              <div className="pt-10 flex flex-col gap-6">
                <button type="submit" className="w-full bg-[#2D2926] text-white py-8 rounded-[32px] font-bold shadow-2xl hover:bg-[#BA7A56] hover:-translate-y-2 transition-all duration-700 active:scale-95 text-lg uppercase tracking-widest">
                  {editingTx ? '確認更新紀錄' : '完成新帳務錄入'}
                </button>
                {editingTx && editingTx.id !== 'sys_bal' && (
                  <button type="button" onClick={() => { if(confirm('這將永久移除此筆藝術足跡，確定嗎？')) { setTransactions(prev => prev.filter(t => t.id !== editingTx.id)); setIsModalOpen(false); } }} className="w-full text-[#D18C8C] font-bold py-4 hover:bg-red-50 rounded-[24px] transition-all text-[10px] uppercase tracking-widest">
                    刪除此筆交易
                  </button>
                )}
              </div>
            </form>
          </div>
        </div>
      )}

      {/* 手機版底部導覽 */}
      <nav className="fixed bottom-0 left-0 w-full bg-white/90 backdrop-blur-3xl border-t border-[#EBE5DE] flex justify-around p-8 lg:hidden z-50 rounded-t-[40px] shadow-2xl">
        <button onClick={() => setView('dashboard')} className={`flex flex-col items-center gap-2 transition-all ${view === 'dashboard' ? 'text-[#BA7A56] scale-110 font-bold' : 'text-[#C4C0BA]'}`}>
           <LayoutDashboard size={24} />
           <span className="text-[9px] uppercase tracking-widest font-bold">總覽</span>
        </button>
        <button onClick={() => setView('students')} className={`flex flex-col items-center gap-2 transition-all ${view === 'students' ? 'text-[#BA7A56] scale-110 font-bold' : 'text-[#C4C0BA]'}`}>
           <Users size={24} />
           <span className="text-[9px] uppercase tracking-widest font-bold">學員</span>
        </button>
        <button onClick={() => setView('courses')} className={`flex flex-col items-center gap-2 transition-all ${view === 'courses' ? 'text-[#BA7A56] scale-110 font-bold' : 'text-[#C4C0BA]'}`}>
           <BookOpen size={24} />
           <span className="text-[9px] uppercase tracking-widest font-bold">課程</span>
        </button>
        <button onClick={() => setView('finance')} className={`flex flex-col items-center gap-2 transition-all ${view === 'finance' ? 'text-[#BA7A56] scale-110 font-bold' : 'text-[#C4C0BA]'}`}>
           <Receipt size={24} />
           <span className="text-[9px] uppercase tracking-widest font-bold">帳務</span>
        </button>
      </nav>
    </div>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Receipt, 
  Settings, 
  Plus, 
  TrendingUp,
  CreditCard,
  Sparkles,
  Download,
  Search,
  Filter,
  X,
  Quote,
  Palette,
  Award,
  PieChart,
  Target,
  Waves,
  Heart,
  Calendar,
  Layers,
  ChevronRight,
  BookOpen
} from 'lucide-react';
import { Transaction, ViewState, StudentStats, Course } from './types';
import { INITIAL_TRANSACTIONS, INITIAL_COURSES, normalizeName, SYSTEM_COLORS } from './constants';
import { GoogleGenAI } from '@google/genai';

// --- 藝術啟發語錄 ---

const ART_QUOTES = [
  { text: "藝術並不是真理。藝術是能讓我們意識到真理的謊言。", author: "畢卡索" },
  { text: "我夢想著繪畫，我繪畫著夢想。", author: "梵谷" },
  { text: "色彩是我永恆的追求。", author: "莫內" },
  { text: "繪畫是詩，而詩是無形的繪畫。", author: "達文西" }
];

// --- 樣式組件 ---

const SidebarItem = ({ active, icon: Icon, label, onClick }: { active: boolean; icon: any; label: string; onClick: () => void }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-6 py-4 rounded-3xl transition-all duration-700 group ${
      active 
      ? 'bg-[#BA7A56] text-white shadow-xl translate-x-1' 
      : 'text-[#857E75] hover:bg-[#F2EDE4] hover:text-[#2D2926]'
    }`}
  >
    <Icon size={18} strokeWidth={active ? 2.5 : 2} className={active ? 'scale-110' : 'group-hover:scale-110 transition-transform'} />
    <span className={`text-sm tracking-wide ${active ? 'font-bold' : 'font-medium'}`}>{label}</span>
  </button>
);

const BentoCard = ({ children, className = "", title, icon: Icon, action, dark = false }: { children?: React.ReactNode, className?: string, title?: string, icon?: any, action?: React.ReactNode, dark?: boolean }) => (
  <div className={`${dark ? 'bg-[#2D2926] text-white' : 'bg-white text-[#2D2926]'} rounded-[40px] p-8 shadow-[0_20px_60px_rgba(0,0,0,0.03)] border border-black/[0.02] hover:shadow-[0_40px_80px_rgba(0,0,0,0.06)] transition-all duration-1000 flex flex-col group ${className}`}>
    {(title || Icon) && (
      <div className="flex justify-between items-start mb-8">
        <div className="flex items-center gap-4">
          {Icon && (
            <div className={`w-12 h-12 ${dark ? 'bg-white/10 text-[#BA7A56]' : 'bg-[#FAF9F6] text-[#BA7A56]'} rounded-2xl flex items-center justify-center transition-transform group-hover:rotate-6 duration-700`}>
              <Icon size={20} />
            </div>
          )}
          {title && <h3 className="text-xl font-serif font-bold tracking-tight">{title}</h3>}
        </div>
        {action}
      </div>
    )}
    <div className="flex-1">{children}</div>
  </div>
);

const MetricStat = ({ label, value, sub, color, icon: Icon }: { label: string; value: string; sub: string; color: string; icon: any }) => (
  <div className="group relative">
    <div className="absolute inset-0 bg-white rounded-[40px] shadow-sm group-hover:shadow-2xl transition-all duration-1000"></div>
    <div className="relative p-10 flex flex-col h-full overflow-hidden">
      <div className="absolute -right-4 -bottom-4 w-24 h-24 opacity-[0.03] group-hover:scale-150 transition-transform duration-1000" style={{ color }}>
         <Icon size={120} />
      </div>
      <div className="flex justify-between items-start mb-8">
        <div className="p-4 rounded-2xl" style={{ backgroundColor: `${color}15`, color }}>
          <Icon size={24} />
        </div>
        <div className="text-right">
          <span className="text-[10px] font-bold text-[#C4C0BA] uppercase tracking-[3px]">{label}</span>
        </div>
      </div>
      <div className="mt-auto relative z-10">
        <h3 className="text-5xl font-bold text-[#2D2926] tracking-tighter font-serif">{value}</h3>
        <p className="text-[11px] text-[#857E75] font-bold mt-4 flex items-center gap-2">
          <TrendingUp size={12} className="text-[#8FA895]" /> {sub}
        </p>
      </div>
    </div>
  </div>
);

// --- 核心應用程式 ---

export default function App() {
  const [view, setView] = useState<ViewState>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('koala_transactions_v16_2');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [courses] = useState<Course[]>(INITIAL_COURSES);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [quote] = useState(() => ART_QUOTES[Math.floor(Math.random() * ART_QUOTES.length)]);

  // 篩選狀態
  const [filterName, setFilterName] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  useEffect(() => {
    localStorage.setItem('koala_transactions_v16_2', JSON.stringify(transactions));
  }, [transactions]);

  // --- 經營邏輯分析 ---

  const analytics = useMemo(() => {
    const year114Txs = transactions.filter(t => t.year === '114' && t.paid);
    const totalRev = year114Txs.reduce((sum, t) => sum + t.amount, 0);
    const unpaid = transactions.filter(t => !t.paid).reduce((sum, t) => sum + t.amount, 0);

    const uniqueStudents = new Set<string>();
    transactions.forEach(t => {
      if (t.name !== '系統結轉' && t.name !== '寵物畫' && t.name !== 'Volvo' && t.name !== '崇學國小' && t.name !== '人物委託') {
        uniqueStudents.add(normalizeName(t.name));
      }
    });

    const monthMap: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.paid) {
        const month = t.date.substring(0, 7);
        monthMap[month] = (monthMap[month] || 0) + t.amount;
      }
    });
    const revenueHistory = Object.entries(monthMap)
      .sort((a, b) => b[0].localeCompare(a[0]))
      .slice(0, 6)
      .reverse();

    const courseMap: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉' || t.name === 'Volvo') return;
      courseMap[t.course] = (courseMap[t.course] || 0) + 1;
    });
    const topCourses = Object.entries(courseMap)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5);

    return { totalRev, unpaid, studentCount: uniqueStudents.size, revenueHistory, topCourses };
  }, [transactions]);

  const topStudents = useMemo(() => {
    const stats: Record<string, StudentStats> = {};
    transactions.forEach(t => {
      if (t.name === '系統結轉' || t.name === '寵物畫' || t.name === 'Volvo' || t.name === '崇學國小' || t.name === '人物委託') return;
      const realName = normalizeName(t.name);
      if (!stats[realName]) {
        stats[realName] = { name: realName, totalSpent: 0, courses: [], lastActive: '', transactionCount: 0 };
      }
      if (t.paid) stats[realName].totalSpent += t.amount;
      if (!stats[realName].courses.includes(t.course)) stats[realName].courses.push(t.course);
      if (t.date > stats[realName].lastActive) stats[realName].lastActive = t.date;
      stats[realName].transactionCount++;
    });
    return Object.values(stats).sort((a, b) => b.totalSpent - a.totalSpent);
  }, [transactions]);

  const filteredFinance = useMemo(() => {
    return transactions.filter(t => {
      const matchesName = t.name.toLowerCase().includes(filterName.toLowerCase()) || t.course.toLowerCase().includes(filterName.toLowerCase());
      const matchesStartDate = startDate ? t.date >= startDate : true;
      const matchesEndDate = endDate ? t.date <= endDate : true;
      return matchesName && matchesStartDate && matchesEndDate;
    });
  }, [transactions, filterName, startDate, endDate]);

  // --- 事件處理 ---

  const runAiConsultant = async () => {
    setIsAnalyzing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `
        角色：Koala Art Studio 專屬經營顧問 (Dr. Wen 的 AI 助手)
        場景：分析當前畫室數據，並提供具有文藝氣息與商業洞察的建議。
        數據：
        - 114年度累計營收: $${analytics.totalRev} (目標達成率 100%)
        - 活躍學員人頭數: ${analytics.studentCount} 位
        - 最受歡迎課程: ${analytics.topCourses.map(c => c[0]).join(', ')}
        - 待核銷帳項: $${analytics.unpaid}
        任務：請提供 3 點經營洞察與 1 個未來的創意企劃建議。口吻請如同與藝術家的深度對話，溫柔且專業。使用繁體中文。
      `;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text || "靈感採集中，請稍後。");
    } catch (err) {
      setAiAnalysis("連接藝術靈感的頻道暫時受阻，請稍後再試。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSaveTx = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const dateStr = formData.get('date') as string;
    const yearPrefix = dateStr.substring(0, 4);
    const newTx: Transaction = {
      id: editingTx?.id || `tx_${Date.now()}`,
      date: dateStr,
      name: formData.get('name') as string,
      course: formData.get('course') as string,
      amount: parseInt(formData.get('amount') as string) || 0,
      paid: formData.get('status') === 'true',
      year: yearPrefix === '2026' ? '115' : yearPrefix === '2025' ? '114' : '113'
    };
    if (editingTx) {
      setTransactions(prev => prev.map(t => t.id === editingTx.id ? newTx : t));
    } else {
      setTransactions(prev => [newTx, ...prev]);
    }
    setIsModalOpen(false);
    setEditingTx(null);
  };

  const exportCSV = () => {
    const headers = "日期,姓名,項目,金額,狀態,年份\n";
    const rows = transactions.map(t => 
      `${t.date},${t.name},${t.course},${t.amount},${t.paid ? '已付' : '未付'},${t.year}`
    ).join("\n");
    const blob = new Blob(["\ufeff" + headers + rows], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", `考拉藝術財務檔案_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="flex min-h-screen bg-[#FAF9F6] selection:bg-[#BA7A56]/20">
      {/* 側邊導覽 */}
      <aside className="w-80 bg-white border-r border-[#EBE5DE] p-10 flex flex-col hidden lg:flex sticky top-0 h-screen overflow-hidden">
        <div className="absolute -left-20 -top-20 w-64 h-64 bg-[#F2EDE4] rounded-full blur-3xl opacity-50"></div>
        <div className="relative z-10">
          <div className="flex items-center gap-5 mb-24 group cursor-pointer">
            <div className="w-16 h-16 bg-[#2D2926] rounded-[24px] flex items-center justify-center text-3xl shadow-2xl group-hover:rotate-12 transition-all duration-1000">🐨</div>
            <div>
              <h1 className="font-serif text-2xl font-bold text-[#2D2926] tracking-tight">考拉藝術</h1>
              <p className="text-[10px] tracking-[5px] text-[#BA7A56] uppercase font-bold mt-2 opacity-80">Studio Hub</p>
            </div>
          </div>

          <nav className="space-y-4 flex-1">
            <SidebarItem active={view === 'dashboard'} icon={LayoutDashboard} label="經營脈動" onClick={() => setView('dashboard')} />
            <SidebarItem active={view === 'students'} icon={Users} label="學員檔案庫" onClick={() => setView('students')} />
            <SidebarItem active={view === 'courses'} icon={BookOpen} label="創作工作室" onClick={() => setView('courses')} />
            <SidebarItem active={view === 'finance'} icon={Receipt} label="財務流水帳" onClick={() => setView('finance')} />
            <SidebarItem active={false} icon={Settings} label="系統設定" onClick={() => {}} />
          </nav>
        </div>

        <div className="mt-auto space-y-10 relative z-10">
          <div className="bg-[#F2EDE4] p-8 rounded-[40px] relative overflow-hidden group">
            <Quote size={24} className="text-[#BA7A56] mb-6 opacity-30" />
            <p className="text-sm font-serif italic text-[#2D2926] leading-relaxed relative z-10">「{quote.text}」</p>
            <div className="mt-6 flex items-center justify-between">
              <span className="text-[10px] font-bold text-[#857E75] uppercase tracking-widest">— {quote.author}</span>
              <Heart size={14} className="text-[#BA7A56] animate-pulse" />
            </div>
          </div>
        </div>
      </aside>

      {/* 主內容區 */}
      <main className="flex-1 p-8 lg:p-20 overflow-y-auto pb-32 lg:pb-20">
        <header className="flex flex-col md:flex-row md:items-end justify-between gap-10 mb-20">
          <div className="space-y-4">
            <h2 className="font-serif text-6xl font-bold text-[#2D2926] tracking-tighter">
              {view === 'dashboard' ? 'Studio Pulse' : view === 'students' ? 'Student Archives' : view === 'courses' ? 'Creative Studio' : 'Financial Ledger'}
            </h2>
            <div className="flex items-center gap-4 text-[#857E75] text-xs font-semibold tracking-[2px] uppercase">
              <span className="w-2 h-2 bg-[#BA7A56] rounded-full animate-ping"></span>
              最後更新：{new Date().toLocaleDateString('zh-TW')}
            </div>
          </div>
          <button 
            onClick={() => { setEditingTx(null); setIsModalOpen(true); }}
            className="bg-[#2D2926] text-white px-12 py-6 rounded-[32px] flex items-center gap-4 shadow-2xl hover:bg-[#BA7A56] transition-all font-bold"
          >
            <Plus size={24} />
            <span className="tracking-widest uppercase text-xs">新增數據</span>
          </button>
        </header>

        {view === 'dashboard' && (
          <div className="space-y-12">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
              <MetricStat label="114年度總營收" value={`$${analytics.totalRev.toLocaleString()}`} sub="數據目標達成：100%" icon={TrendingUp} color="#BA7A56" />
              <MetricStat label="活躍學員人頭" value={`${analytics.studentCount}`} sub="去重後真實學員數" icon={Users} color="#8A9A8A" />
              <MetricStat label="待核銷流水" value={`$${analytics.unpaid.toLocaleString()}`} sub="現金流穩定性指標" icon={CreditCard} color="#857E75" />
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
              <BentoCard className="xl:col-span-8" title="營收成長軌跡" icon={Waves}>
                <div className="h-72 flex items-end justify-between px-10 gap-10 pt-12">
                  {analytics.revenueHistory.map(([month, amount]) => (
                    <div key={month} className="flex-1 flex flex-col items-center group relative h-full justify-end">
                      <div className="w-full max-w-[50px] bg-[#FAF9F6] rounded-3xl relative overflow-hidden transition-all">
                         <div 
                          className="absolute bottom-0 left-0 w-full bg-[#BA7A56] rounded-3xl transition-all"
                          style={{ height: `${(amount / (Math.max(...analytics.revenueHistory.map(m => m[1])) || 1)) * 100}%` }}
                        />
                      </div>
                      <span className="mt-6 text-[11px] font-bold text-[#C4C0BA]">{month.split('-')[1]}月</span>
                    </div>
                  ))}
                </div>
              </BentoCard>

              <BentoCard className="xl:col-span-4" title="熱門媒材排行榜" icon={PieChart}>
                <div className="space-y-8 pt-4">
                  {analytics.topCourses.map(([course, count], idx) => (
                    <div key={course} className="space-y-4">
                      <div className="flex justify-between items-center text-xs">
                        <span className="font-bold text-[#2D2926]">{course}</span>
                        <span className="text-[#BA7A56] font-bold">{count} 堂</span>
                      </div>
                      <div className="h-1.5 w-full bg-[#FAF9F6] rounded-full overflow-hidden">
                        <div 
                          className="h-full rounded-full transition-all"
                          style={{ 
                            width: `${(count / (transactions.length || 1)) * 100}%`,
                            backgroundColor: idx === 0 ? '#BA7A56' : '#8A9A8A'
                          }}
                        />
                      </div>
                    </div>
                  ))}
                </div>
              </BentoCard>
            </div>

            <BentoCard dark title="AI 經營點評" icon={Sparkles}>
              <div className="min-h-[200px] flex flex-col gap-8">
                <div className="flex-1 text-white/80 leading-relaxed text-sm">
                  {isAnalyzing ? "正在深讀畫室數據..." : aiAnalysis || "「點擊下方按鈕，開啟與 Gemini 的經營深度對談。」"}
                </div>
                <button onClick={runAiConsultant} disabled={isAnalyzing} className="w-full bg-[#BA7A56] text-white py-6 rounded-[32px] font-bold flex items-center justify-center gap-4 shadow-xl">
                   <Sparkles size={20} />
                   {isAnalyzing ? "分析中..." : "啟動 AI 數據洞察"}
                </button>
              </div>
            </BentoCard>
          </div>
        )}

        {view === 'students' && (
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-10">
            {topStudents.map((s) => (
              <div key={s.name} className="bg-white p-12 rounded-[48px] shadow-sm border border-[#EBE5DE] hover:shadow-2xl transition-all">
                <div className="flex justify-between items-start mb-12">
                  <div className="w-20 h-20 bg-[#2D2926] rounded-3xl flex items-center justify-center text-3xl font-serif font-bold text-[#BA7A56]">
                    {s.name[0]}
                  </div>
                  <div className="text-right">
                    <span className="text-[10px] uppercase tracking-widest text-[#C4C0BA] font-bold">總消費額</span>
                    <h4 className="text-3xl font-serif font-bold text-[#2D2926] mt-2">${s.totalSpent.toLocaleString()}</h4>
                  </div>
                </div>
                <h3 className="text-2xl font-serif font-bold text-[#2D2926] mb-3">{s.name}</h3>
                <p className="text-xs text-[#857E75] mb-10">參與 {s.transactionCount} 次創作 / 最近：{s.lastActive}</p>
                <div className="flex flex-wrap gap-2">
                  {s.courses.slice(0, 3).map(c => (
                    <span key={c} className="bg-[#FAF9F6] text-[#857E75] px-4 py-2 rounded-xl text-[9px] font-bold">{c}</span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}

        {view === 'courses' && (
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-10">
            {courses.map(course => (
              <div key={course.id} className="bg-white rounded-[48px] overflow-hidden shadow-sm border border-[#EBE5DE] hover:shadow-xl transition-all">
                <div className="h-40" style={{ backgroundColor: course.color + '20' }} />
                <div className="p-10 space-y-6">
                  <h3 className="text-xl font-serif font-bold text-[#2D2926]">{course.title}</h3>
                  <p className="text-sm text-[#857E75] line-clamp-2">{course.description}</p>
                  <div className="flex items-center justify-between pt-4">
                     <span className="text-2xl font-serif font-bold text-[#BA7A56]">${course.price.toLocaleString()}</span>
                     <button className="w-10 h-10 rounded-full bg-[#FAF9F6] flex items-center justify-center text-[#2D2926]">
                        <ChevronRight size={18} />
                     </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {view === 'finance' && (
          <div className="space-y-12">
            <BentoCard className="!p-10" title="數據篩選" icon={Filter}>
              <div className="grid grid-cols-1 md:grid-cols-12 gap-8 items-end">
                <div className="md:col-span-6">
                  <div className="relative">
                    <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-[#C4C0BA]" size={20} />
                    <input type="text" value={filterName} onChange={(e) => setFilterName(e.target.value)} placeholder="搜尋學員、媒材、課程名稱..." className="w-full bg-[#FAF9F6] border-0 rounded-[24px] pl-16 pr-8 py-5 text-sm font-medium" />
                  </div>
                </div>
                <div className="md:col-span-3">
                   <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-[#FAF9F6] border-0 rounded-[24px] px-8 py-5 text-sm font-medium" />
                </div>
                <div className="md:col-span-3 flex gap-4">
                  <button onClick={() => {setFilterName(''); setStartDate('');}} className="flex-1 bg-white border border-[#EBE5DE] py-5 rounded-[24px] text-[10px] font-bold uppercase tracking-widest">重設</button>
                  <button onClick={exportCSV} className="flex-1 bg-[#2D2926] text-white py-5 rounded-[24px] text-[10px] font-bold uppercase tracking-widest">導出</button>
                </div>
              </div>
            </BentoCard>

            <div className="bg-white rounded-[48px] shadow-sm border border-[#EBE5DE] overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-[#FAF9F6] text-[#C4C0BA] text-[10px] font-bold uppercase tracking-[2px]">
                    <tr>
                      <th className="px-12 py-8">日期</th>
                      <th className="px-8 py-8">學員對象 / 項目</th>
                      <th className="px-8 py-8 text-right">金額</th>
                      <th className="px-8 py-8 text-right">狀態</th>
                      <th className="px-12 py-8 text-right"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-[#EBE5DE]/30">
                    {filteredFinance.map(t => (
                      <tr key={t.id} className="hover:bg-[#FAF9F6]/50 transition-all">
                        <td className="px-12 py-8 text-xs font-semibold text-[#857E75]">{t.date}</td>
                        <td className="px-8 py-8">
                          <p className="font-serif font-bold text-lg text-[#2D2926]">{t.name}</p>
                          <p className="text-[10px] text-[#C4C0BA] font-bold uppercase mt-1">{t.course}</p>
                        </td>
                        <td className="px-8 py-8 text-right font-serif font-bold text-[#2D2926] text-xl">${t.amount.toLocaleString()}</td>
                        <td className="px-8 py-8 text-right">
                          <span className={`px-4 py-1.5 rounded-full text-[9px] font-bold uppercase tracking-widest ${t.paid ? 'bg-[#E8F5E9] text-[#388E3C]' : 'bg-[#FFEBEE] text-[#D32F2F]'}`}>
                            {t.paid ? '已入帳' : '待核銷'}
                          </span>
                        </td>
                        <td className="px-12 py-8 text-right">
                          <button onClick={() => { setEditingTx(t); setIsModalOpen(true); }} className="text-[#C4C0BA] hover:text-[#BA7A56] p-2">
                            <Layers size={18} />
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* 編輯視窗 */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-[#2D2926]/40 backdrop-blur-xl">
          <div className="bg-white w-full max-w-xl rounded-[64px] shadow-2xl p-16 animate-in zoom-in">
            <div className="flex justify-between items-center mb-12">
               <h2 className="font-serif text-3xl font-bold text-[#2D2926]">{editingTx ? '修改紀錄' : '新增報名'}</h2>
               <button onClick={() => setIsModalOpen(false)} className="text-[#C4C0BA]"><X size={28} /></button>
            </div>
            <form onSubmit={handleSaveTx} className="space-y-8">
              <div className="grid grid-cols-2 gap-6">
                <input name="date" type="date" required defaultValue={editingTx?.date || new Date().toISOString().split('T')[0]} className="w-full bg-[#FAF9F6] border-0 rounded-[20px] px-6 py-4 text-sm font-bold" />
                <select name="status" defaultValue={editingTx?.paid ? 'true' : 'false'} className="w-full bg-[#FAF9F6] border-0 rounded-[20px] px-6 py-4 text-sm font-bold">
                  <option value="true">已完成付款</option>
                  <option value="false">尚未付款</option>
                </select>
              </div>
              <input name="name" type="text" placeholder="學員姓名" required defaultValue={editingTx?.name || ''} className="w-full bg-[#FAF9F6] border-0 rounded-[20px] px-6 py-4 text-sm font-bold" />
              <input name="course" type="text" placeholder="課程名稱 / 項目" required defaultValue={editingTx?.course || ''} className="w-full bg-[#FAF9F6] border-0 rounded-[20px] px-6 py-4 text-sm font-bold" />
              <div className="relative">
                <span className="absolute left-6 top-1/2 -translate-y-1/2 text-[#C4C0BA] font-serif font-bold text-2xl">$</span>
                <input name="amount" type="number" placeholder="金額" required defaultValue={editingTx?.amount || ''} className="w-full bg-[#FAF9F6] border-0 rounded-[20px] pl-12 pr-6 py-6 font-serif font-bold text-3xl" />
              </div>
              <button type="submit" className="w-full bg-[#2D2926] text-white py-6 rounded-[28px] font-bold shadow-xl hover:bg-[#BA7A56] transition-all">
                確認儲存
              </button>
            </form>
          </div>
        </div>
      )}

      {/* 手機底部導覽 */}
      <nav className="fixed bottom-0 left-0 w-full bg-white/95 backdrop-blur-xl border-t border-[#EBE5DE] flex justify-around p-6 lg:hidden z-50 rounded-t-[40px]">
        <button onClick={() => setView('dashboard')} className={view === 'dashboard' ? 'text-[#BA7A56]' : 'text-[#C4C0BA]'}><LayoutDashboard size={24} /></button>
        <button onClick={() => setView('students')} className={view === 'students' ? 'text-[#BA7A56]' : 'text-[#C4C0BA]'}><Users size={24} /></button>
        <button onClick={() => setView('courses')} className={view === 'courses' ? 'text-[#BA7A56]' : 'text-[#C4C0BA]'}><BookOpen size={24} /></button>
        <button onClick={() => setView('finance')} className={view === 'finance' ? 'text-[#BA7A56]' : 'text-[#C4C0BA]'}><Receipt size={24} /></button>
      </nav>
    </div>
  );
}
